  1→import { useState } from "react";
  2→import { X, Plus, History, PanelLeftClose } from "lucide-react";
  3→import { CircularPixelGrid } from "@/features/session/ui/CircularPixelGrid";
  4→import {
  5→  DndContext,
  6→  closestCenter,
  7→  PointerSensor,
  8→  useSensor,
  9→  useSensors,
 10→  type DragEndEvent,
 11→} from "@dnd-kit/core";
 12→import { arrayMove, SortableContext, horizontalListSortingStrategy } from "@dnd-kit/sortable";
 13→import { Tooltip, TooltipContent, TooltipTrigger, TooltipKbd } from "@/components/ui/tooltip";
 14→import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
 15→import { cn } from "@/shared/lib/utils";
 16→import { getAgentLogo } from "@/assets/agents";
 17→import { SortableTab } from "./SortableTab";
 18→
 19→/**
 20→ * Tab data structure — chat sessions only.
 21→ */
 22→export interface Tab {
 23→  id: string;
 24→  label: string;
 25→  data?: {
 26→    sessionId?: string;
 27→    agentType?: string;
 28→    hasStarted?: boolean;
 29→    /** Pre-selected model when tab is created from locked-group picker */
 30→    initialModel?: string;
 31→  };
 32→}
 33→
 34→/** Info preserved when a chat tab is closed, for restore */
 35→export interface ClosedTab {
 36→  label: string;
 37→  sessionId: string;
 38→  agentType?: string;
 39→  closedAt: number;
 40→}
 41→
 42→interface MainContentTabBarProps {
 43→  tabs: Tab[];
 44→  activeTabId: string;
 45→  /** Set of session IDs currently in "working" status — per-tab spinners */
 46→  workingSessionIds?: Set<string>;
 47→  onTabChange: (tabId: string) => void;
 48→  onTabClose?: (tabId: string) => void;
 49→  onTabAdd?: () => void;
 50→  onTabReorder?: (reorderedTabs: Tab[]) => void;
 51→  closedTabs?: ClosedTab[];
 52→  onTabRestore?: (closedTab: ClosedTab) => void;
 53→  onCollapseChatPanel?: () => void;
 54→}
 55→
 56→const ICON_SIZE = "w-3.5 h-3.5";
 57→const EMPTY_CLOSED_TABS: ClosedTab[] = [];
 58→
 59→/** Render tab icon — shows CircularPixelGrid spinner when working, agent logo otherwise. */
 60→function getTabIcon(tab: Tab, isWorking: boolean) {
 61→  if (isWorking) {
 62→    return <CircularPixelGrid variant="generating" size={14} resolution={8} />;
 63→  }
 64→  const LogoComponent = getAgentLogo(tab.data?.agentType || "claude");
 65→  if (LogoComponent) {
 66→    return <LogoComponent className={cn(ICON_SIZE, "flex-shrink-0")} />;
 67→  }
 68→  return null;
 69→}
 70→
 71→function getClosedTabIcon(agentType?: string) {
 72→  const LogoComponent = getAgentLogo(agentType || "claude");
 73→  if (LogoComponent) {
 74→    return <LogoComponent className={cn(ICON_SIZE, "flex-shrink-0")} />;
 75→  }
 76→  return null;
 77→}
 78→
 79→/**
 80→ * MainContentTabBar — tabs-only bar for the chat area.
 81→ * Workspace context (repo, branch, PR actions) moved to WorkspaceHeader.
 82→ *
 83→ * Close rules:
 84→ * - Any tab can be closed as long as at least one tab remains
 85→ * - The close button only appears on hover when there are 2+ tabs
 86→ */
 87→const EMPTY_WORKING_SET = new Set<string>();
 88→
 89→export function MainContentTabBar({
 90→  tabs,
 91→  activeTabId,
 92→  workingSessionIds = EMPTY_WORKING_SET,
 93→  onTabChange,
 94→  onTabClose,
 95→  onTabAdd,
 96→  onTabReorder,
 97→  closedTabs = EMPTY_CLOSED_TABS,
 98→  onTabRestore,
 99→  onCollapseChatPanel,
100→}: MainContentTabBarProps) {
101→  const [restoreOpen, setRestoreOpen] = useState(false);
102→  const canCloseTabs = tabs.length > 1;
103→
104→  // dnd-kit: 5px distance threshold prevents accidental drags when clicking tabs
105→  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 5 } }));
106→
107→  function handleDragEnd(event: DragEndEvent) {
108→    const { active, over } = event;
109→    if (!over || active.id === over.id || !onTabReorder) return;
110→
111→    const oldIndex = tabs.findIndex((t) => t.id === active.id);
112→    const newIndex = tabs.findIndex((t) => t.id === over.id);
113→    if (oldIndex === -1 || newIndex === -1) return;
114→
115→    onTabReorder(arrayMove(tabs, oldIndex, newIndex));
116→  }
117→
118→  return (
119→    <div className="drag-region chat-tabs-header relative z-20 flex h-10 flex-shrink-0 items-center px-2.5">
120→      <div
121→        role="tablist"
122→        className="scrollbar-hidden relative z-[1] flex min-w-0 flex-1 items-center gap-1.5 overflow-x-auto"
123→      >
124→        <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
125→          <SortableContext items={tabs.map((t) => t.id)} strategy={horizontalListSortingStrategy}>
126→            {tabs.map((tab) => {
127→              const isActive = tab.id === activeTabId;
128→              // Per-tab working status: each tab checks its own session ID
129→              // against the working set (populated by useWorkingSessionIds).
130→              const isWorking = !!tab.data?.sessionId && workingSessionIds.has(tab.data.sessionId);
131→
132→              return (
133→                <SortableTab key={tab.id} id={tab.id}>
134→                  <div
135→                    role="tab"
136→                    aria-selected={isActive}
137→                    tabIndex={0}
138→                    onClick={() => onTabChange(tab.id)}
139→                    onKeyDown={(e) => {
140→                      if (e.key === "Enter" || e.key === " ") {
141→                        e.preventDefault();
142→                        onTabChange(tab.id);
143→                      }
144→                    }}
145→                    className={cn(
146→                      "group relative flex items-center gap-1.5 overflow-hidden",
147→                      "h-7 max-w-[200px] min-w-[80px] rounded-lg px-2",
148→                      "cursor-pointer text-base font-normal",
149→                      "transition-colors duration-150",
150→                      isActive
151→                        ? "bg-bg-raised text-text-secondary"
152→                        : "text-text-muted hover:text-text-tertiary"
153→                    )}
154→                  >
155→                    {getTabIcon(tab, isWorking)}
156→
157→                    <div className="min-w-0 flex-1">
158→                      <span className="block truncate">{tab.label}</span>
159→                    </div>
160→
161→                    {/* Close button — overlays right edge on hover, only when 2+ tabs */}
162→                    {onTabClose && canCloseTabs && (
163→                      <div
164→                        className={cn(
165→                          "absolute inset-y-0 right-0 flex items-center pr-1.5 pl-4",
166→                          "opacity-0 transition-opacity duration-150 group-hover:opacity-100",
167→                          isActive
168→                            ? "from-bg-raised bg-gradient-to-l from-50% to-transparent"
169→                            : "from-bg-surface group-hover:from-bg-surface bg-gradient-to-l from-50% to-transparent"
170→                        )}
171→                      >
172→                        <button
173→                          type="button"
174→                          onClick={(e) => {
175→                            e.stopPropagation();
176→                            onTabClose(tab.id);
177→                          }}
178→                          className={cn(
179→                            "flex h-4 w-4 items-center justify-center rounded-sm",
180→                            "transition-colors duration-150",
181→                            "hover:bg-bg-muted"
182→                          )}
183→                          aria-label={`Close ${tab.label} tab`}
184→                        >
185→                          <X className="h-2.5 w-2.5" />
186→                        </button>
187→                      </div>
188→                    )}
189→                  </div>
190→                </SortableTab>
191→              );
192→            })}
193→          </SortableContext>
194→        </DndContext>
195→
196→        {/* New tab button — stays adjacent to tabs */}
197→        {onTabAdd && (
198→          <Tooltip delayDuration={200}>
199→            <TooltipTrigger asChild>
200→              <button
201→                type="button"
202→                aria-label="New chat tab"
203→                onClick={() => onTabAdd?.()}
204→                className={cn(
205→                  "flex items-center justify-center",
206→                  "h-7 flex-shrink-0 rounded-lg px-1.5",
207→                  "text-text-disabled hover:text-text-muted",
208→                  "transition-colors duration-150"
209→                )}
210→              >
211→                <Plus className="h-4 w-4" />
212→              </button>
213→            </TooltipTrigger>
214→            <TooltipContent side="bottom">
215→              <div className="flex items-center gap-3">
216→                <span className="text-xs">New chat</span>
217→                <TooltipKbd>⌘T</TooltipKbd>
218→              </div>
219→            </TooltipContent>
220→          </Tooltip>
221→        )}
222→      </div>
223→
224→      {/* History button — pinned far right, outside scrollable area */}
225→      {onTabRestore && closedTabs.length > 0 && (
226→        <Popover open={restoreOpen} onOpenChange={setRestoreOpen}>
227→          <Tooltip delayDuration={200}>
228→            <TooltipTrigger asChild>
229→              <PopoverTrigger asChild>
230→                <button
231→                  type="button"
232→                  aria-label="Restore closed session"
233→                  className={cn(
234→                    "flex items-center justify-center",
235→                    "h-7 flex-shrink-0 rounded-lg px-1.5",
236→                    "text-text-disabled hover:text-text-muted",
237→                    "transition-colors duration-150"
238→                  )}
239→                >
240→                  <History className="h-3.5 w-3.5" />
241→                </button>
242→              </PopoverTrigger>
243→            </TooltipTrigger>
244→            {!restoreOpen && (
245→              <TooltipContent side="bottom">
246→                <p className="text-xs">Restore closed session (⌘⇧T)</p>
247→              </TooltipContent>
