135→
136→  const repos = reposQuery.data || [];
137→  const username = settingsQuery.data?.user_name || "My Account";
138→
139→  // GitHub CLI status — gates PR polling (like Codex)
140→  const ghStatusQuery = useGhStatus();
141→
