/**
 * Unread Session Store
 *
 * Tracks which sessions have unseen activity (agent finished working,
 * errored, or needs response while user wasn't viewing that session).
 *
 * This is purely frontend state — no DB column needed. The store is
 * persisted to localStorage so unread indicators survive page refreshes.
 *
 * Mark as unread: when session transitions from "working" to any terminal
 * state (idle, error, needs_response, needs_plan_response) and the user
 * is not currently viewing that session.
 *
 * Mark as read: when user clicks on a workspace or switches to a tab
 * containing the session.
 */

import { create } from "zustand";
import { devtools, persist } from "zustand/middleware";

interface UnreadStore {
  /** Set of session IDs with unseen activity */
  unreadSessionIds: Record<string, true>;

  /** Mark a session as having unseen activity */
  markUnread: (sessionId: string) => void;

  /** Mark a session as read (user viewed it) */
  markRead: (sessionId: string) => void;

  /** Check if a session has unseen activity */
  isUnread: (sessionId: string) => boolean;
}

export const useUnreadStore = create<UnreadStore>()(
  devtools(
    persist(
      (set, get) => ({
        unreadSessionIds: {},

        markUnread: (sessionId) =>
          set(
            (state) => ({
              unreadSessionIds: { ...state.unreadSessionIds, [sessionId]: true as const },
            }),
            false,
            "unread/markUnread"
          ),

        markRead: (sessionId) =>
          set(
            (state) => {
              if (!state.unreadSessionIds[sessionId]) return state;
              const { [sessionId]: _, ...rest } = state.unreadSessionIds;
              return { unreadSessionIds: rest };
            },
            false,
            "unread/markRead"
          ),

        isUnread: (sessionId) => !!get().unreadSessionIds[sessionId],
      }),
      {
        name: "unread-sessions-store",
        version: 1,
      }
    ),
    {
      name: "unread-sessions-store",
      enabled: import.meta.env.DEV,
    }
  )
);

/**
 * Stable actions — call from anywhere without causing re-renders.
 * Use these in effects, event handlers, and non-React code.
 */
export const unreadActions = {
  markUnread: (sessionId: string) => useUnreadStore.getState().markUnread(sessionId),
  markRead: (sessionId: string) => useUnreadStore.getState().markRead(sessionId),
  isUnread: (sessionId: string) => useUnreadStore.getState().isUnread(sessionId),
};

