  1→/**
  2→ * Chat Area — renders the active chat tab and wires up the tab bar.
  3→ *
  4→ * Tab lifecycle (create, close, restore, labels) is managed by useChatTabs.
  5→ * This component focuses on layout and connecting tabs to SessionPanel.
  6→ */
  7→
  8→import { useMemo, useEffect } from "react";
  9→import type { Dispatch, SetStateAction } from "react";
 10→import { SessionPanel } from "@/features/session";
 11→import type { SessionPanelRef } from "@/features/session";
 12→import { useWorkingSessionIds } from "@/features/session/api/session.queries";
 13→import { useUnreadStore, unreadActions } from "@/features/session/store/unreadStore";
 14→import { WorkspaceEmptyState } from "@/features/session/ui/WorkspaceEmptyState";
 15→import { MainContentTabBar } from "@/features/workspace";
 16→import type { Workspace } from "@/shared/types";
 17→import { useChatTabs } from "./useChatTabs";
 18→
 19→const EMPTY_UNREAD_SET = new Set<string>();
 20→
 21→interface ChatAreaProps {
 22→  workspace: Workspace;
 23→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 24→  onCreatePRHandlerChange: (handler: (() => void) | null) => void;
 25→  onSendAgentMessageHandlerChange: Dispatch<
 26→    SetStateAction<((text: string) => Promise<void>) | null>
 27→  >;
 28→  onCollapseChatPanel?: () => void;
 29→}
 30→
 31→export function ChatArea({
 32→  workspace,
 33→  workspaceChatPanelRef,
 34→  onCreatePRHandlerChange,
 35→  onSendAgentMessageHandlerChange,
 36→  onCollapseChatPanel,
 37→}: ChatAreaProps) {
 38→  const {
 39→    tabs,
 40→    activeTabId,
 41→    activeTab,
 42→    closedTabs,
 43→    handleTabChange,
 44→    handleTabClose,
 45→    handleTabAdd,
 46→    handleTabReorder,
 47→    handleTabRestore,
 48→    updateChatTabAgentType,
 49→    markChatTabStarted,
 50→  } = useChatTabs({
 51→    workspaceId: workspace.id,
 52→    activeSessionId: workspace.current_session_id,
 53→  });
 54→
 55→  // Resolve sessionId: tab's own session, falling back to workspace's active session
 56→  const tabSessionId = activeTab?.data?.sessionId || workspace.current_session_id;
 57→
 58→  // Per-tab working status: subscribes to each chat tab's session detail cache
 59→  // so each tab's spinner reflects its own session's status (not the workspace's
 60→  // single session_status which breaks with multiple tabs).
 61→  const chatSessionIds = useMemo(
 62→    () => tabs.filter((t) => t.data?.sessionId).map((t) => t.data!.sessionId!),
 63→    [tabs]
 64→  );
 65→  const workingSessionIds = useWorkingSessionIds(chatSessionIds);
 66→
 67→  // Unread tracking: subscribe only to this workspace's session IDs to avoid
 68→  // cross-workspace re-renders. The stringified key ensures referential stability.
 69→  const unreadKey = useUnreadStore((s) => {
 70→    let key = "";
 71→    for (const sid of chatSessionIds) {
 72→      if (s.unreadSessionIds[sid]) key += sid + ",";
 73→    }
 74→    return key;
 75→  });
 76→  const unreadSessionIds = useMemo(() => {
 77→    if (!unreadKey) return EMPTY_UNREAD_SET;
 78→    const ids = new Set<string>();
 79→    for (const sid of unreadKey.split(",")) {
 80→      if (sid) ids.add(sid);
 81→    }
 82→    return ids;
 83→  }, [unreadKey]);
 84→
 85→  // Mark the active tab's session as read when it becomes active
 86→  const activeSessionId = activeTab?.data?.sessionId;
 87→  useEffect(() => {
 88→    if (activeSessionId) {
 89→      unreadActions.markRead(activeSessionId);
 90→    }
 91→  }, [activeSessionId]);
 92→
 93→  return (
 94→    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
 95→      <MainContentTabBar
 96→        tabs={tabs}
 97→        activeTabId={activeTabId}
 98→        workingSessionIds={workingSessionIds}
 99→        unreadSessionIds={unreadSessionIds}
100→        onTabChange={handleTabChange}
101→        onTabClose={handleTabClose}
102→        onTabAdd={handleTabAdd}
103→        onTabReorder={handleTabReorder}
104→        closedTabs={closedTabs}
105→        onTabRestore={handleTabRestore}
106→        onCollapseChatPanel={onCollapseChatPanel}
107→      />
108→
109→      <div className="flex min-h-0 flex-1 flex-col overflow-hidden">
110→        {tabSessionId && (
111→          <SessionPanel
112→            key={tabSessionId}
113→            ref={workspaceChatPanelRef}
114→            sessionId={tabSessionId}
115→            workspaceId={workspace.id}
116→            workspacePath={workspace.workspace_path}
117→            workspaceRepoName={workspace.repo_name}
118→            workspaceParentBranch={workspace.git_target_branch}
119→            workspaceDefaultBranch={workspace.git_default_branch}
120→            isFirstSession={workspace.latest_message_sent_at === null}
121→            embedded={true}
122→            initialModel={activeTab?.data?.initialModel}
123→            onAgentTypeChange={(agentType) =>
124→              activeTab && updateChatTabAgentType(activeTab.id, agentType)
125→            }
126→            onSessionStarted={() => activeTab && markChatTabStarted(activeTab.id)}
127→            onOpenNewTab={handleTabAdd}
128→            onCreatePR={(handler) => onCreatePRHandlerChange(() => handler)}
129→            onSendAgentMessage={(handler) => onSendAgentMessageHandlerChange(() => handler)}
130→          />
131→        )}
132→
133→        {/* Workspace still initializing — show the same empty state with init progress */}
134→        {!tabSessionId && (
135→          <WorkspaceEmptyState
136→            repoName={workspace.repo_name}
137→            parentBranch={workspace.git_target_branch}
138→            isFirstSession={true}
139→            initializing={workspace.state === "initializing"}
140→            initStep={workspace.init_stage}
141→          />
