  1→/**
  2→ * Sidebar Status Configuration System
  3→ *
  4→ * Centralized configuration for workspace/session statuses, priorities, and visual styling.
  5→ * Design philosophy: Make it easy to iterate on colors and priorities without touching component code.
  6→ *
  7→ * @see src/features/session/types.ts for SessionStatus type definition
  8→ */
  9→
 10→import type { Workspace } from "@/features/workspace/types";
 11→import type { WorkspaceStatus } from "@shared/enums";
 12→
 13→/**
 14→ * Display status extends SessionStatus with derived states.
 15→ * 'unread' is derived from needs_response / needs_plan_response session status.
 16→ */
 17→export type DisplayStatus = "idle" | "working" | "error" | "unread";
 18→
 19→/**
 20→ * Priority levels for sorting (higher = more urgent)
 21→ */
 22→export enum StatusPriority {
 23→  ERROR = 4, // Critical - something broke
 24→  UNREAD = 3, // Important - needs review / response
 25→  WORKING = 2, // Active - in progress
 26→  IDLE = 0, // Dormant - no activity
 27→}
 28→
 29→/**
 30→ * Visual configuration for each status
 31→ *
 32→ * Design System:
 33→ * - badge: Color for notification badges (collapsed sidebar)
 34→ * - border: Border/glow color for active states
 35→ * - text: Text color for status labels
 36→ * - bg: Background color for sections/cards
 37→ *
 38→ * Color Semantics:
 39→ * 🔴 Red (error) = Critical, blocking, needs immediate action
 40→ * 🟡 Amber (unread) = Important, needs attention when ready
 41→ * 🟢 Green (working) = Active, positive, making progress
 42→ * 🟣 Purple (compacting) = Transient, maintenance, ignore
 43→ * ⚪ Gray (idle) = Dormant, background, low priority
 44→ */
 45→export interface StatusConfig {
 46→  priority: StatusPriority;
 47→  label: string;
 48→  labelActive: string; // Present continuous form (e.g., "Working...")
 49→  badge: string; // Tailwind classes for badge
 50→  border: string; // Tailwind classes for border/glow
 51→  text: string; // Tailwind classes for text
 52→  bg: string; // Tailwind classes for background
 53→  pulse?: boolean; // Whether to animate/pulse
 54→}
 55→
 56→/**
 57→ * Status configuration map
 58→ *
 59→ * IMPORTANT: To change colors, edit this object (no component changes needed)
 60→ */
 61→export const STATUS_CONFIG: Record<DisplayStatus, StatusConfig> = {
 62→  error: {
 63→    priority: StatusPriority.ERROR,
 64→    label: "Error",
 65→    labelActive: "Error",
 66→    badge: "bg-destructive text-destructive-foreground",
 67→    border: "border-destructive/60",
 68→    text: "text-destructive",
 69→    bg: "bg-destructive/10",
 70→    pulse: true,
 71→  },
 72→  unread: {
 73→    priority: StatusPriority.UNREAD,
 74→    label: "Needs Response",
 75→    labelActive: "Awaiting Input",
 76→    badge: "bg-status-unread text-status-unread-fg",
 77→    border: "border-status-unread/60",
 78→    text: "text-status-unread",
 79→    bg: "bg-status-unread/10",
 80→    pulse: false,
 81→  },
 82→  working: {
 83→    priority: StatusPriority.WORKING,
 84→    label: "Working",
 85→    labelActive: "Working...",
 86→    badge: "bg-primary text-primary-foreground",
 87→    border: "border-primary/60",
 88→    text: "text-primary",
 89→    bg: "bg-primary/10",
 90→    pulse: true,
 91→  },
 92→  idle: {
 93→    priority: StatusPriority.IDLE,
 94→    label: "Idle",
 95→    labelActive: "Idle",
 96→    badge: "bg-muted text-muted-foreground",
 97→    border: "border-muted",
 98→    text: "text-muted-foreground",
 99→    bg: "bg-muted/30",
100→    pulse: false,
101→  },
102→};
103→
104→// ── Workflow Status (Linear-style) ────────────────────────────────────────
105→// Separate from DisplayStatus which shows real-time agent activity.
106→// Rendered as a small icon to the left of the workspace title.
107→
108→export interface WorkflowStatusConfig {
109→  label: string;
110→  color: string;
111→}
112→
113→export const WORKFLOW_STATUS_CONFIG: Record<WorkspaceStatus, WorkflowStatusConfig> = {
114→  backlog: { label: "Backlog", color: "text-muted-foreground" },
115→  "in-progress": { label: "In Progress", color: "text-status-in-progress" },
116→  "in-review": { label: "In Review", color: "text-status-in-review" },
117→  done: { label: "Done", color: "text-status-done" },
118→  canceled: { label: "Canceled", color: "text-muted-foreground" },
119→};
120→
121→/**
122→ * Derive display status from workspace data
123→ *
124→ * Priority logic:
125→ * 1. Error — session in error state
126→ * 2. Unread — agent needs user response (needs_response / needs_plan_response)
127→ * 3. Working — agent actively processing
128→ * 4. Idle — dormant
129→ *
130→ * @param workspace Workspace data with session info
131→ * @returns Derived display status for UI rendering
132→ */
133→export function getDisplayStatus(workspace: Workspace): DisplayStatus {
134→  const status = workspace.session_status;
135→
136→  if (status === "error") return "error";
137→  if (status === "needs_response" || status === "needs_plan_response") return "unread";
138→  if (status === "working") return "working";
139→  return "idle";
140→}
141→
142→/**
143→ * Check if workspace needs user attention.
144→ * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
145→ */
146→export function getUnreadCount(workspace: Workspace): number {
147→  const status = workspace.session_status;
148→  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
149→}
150→
151→/**
152→ * Sort workspaces by status priority
153→ * Higher priority statuses appear first
154→ *
155→ * @param workspaces Array of workspaces to sort
156→ * @returns Sorted array (original array not mutated)
157→ */
158→export function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
159→  return [...workspaces].sort((a, b) => {
160→    const statusA = getDisplayStatus(a);
161→    const statusB = getDisplayStatus(b);
162→    const priorityA = STATUS_CONFIG[statusA].priority;
163→    const priorityB = STATUS_CONFIG[statusB].priority;
164→
165→    // Higher priority first
166→    if (priorityA !== priorityB) {
167→      return priorityB - priorityA;
168→    }
169→
170→    // Same priority: sort by latest activity (most recent first)
171→    const timeA = new Date(a.updated_at).getTime();
172→    const timeB = new Date(b.updated_at).getTime();
173→    return timeB - timeA;
174→  });
175→}
176→
177→/**
178→ * Group workspaces by display status
179→ * Used for rendering section headers in expanded sidebar
180→ *
181→ * @param workspaces Array of workspaces to group
182→ * @returns Object with status as keys, workspace arrays as values
183→ */
184→export function groupByStatus<T extends Workspace>(
185→  workspaces: T[]
186→): Partial<Record<DisplayStatus, T[]>> {
187→  const groups: Partial<Record<DisplayStatus, T[]>> = {};
188→
189→  workspaces.forEach((workspace) => {
190→    const status = getDisplayStatus(workspace);
191→    if (!groups[status]) {
192→      groups[status] = [];
193→    }
194→    groups[status]!.push(workspace);
195→  });
196→
197→  return groups;
198→}
199→
200→/**
201→ * Get aggregate status counts for a repository
202→ * Used for collapsed sidebar status indicators
203→ *
204→ * @param workspaces Workspaces in a repository
205→ * @returns Count of each status type
206→ */
207→export function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
208→  const counts: Record<DisplayStatus, number> = {
209→    error: 0,
210→    unread: 0,
211→    working: 0,
212→    idle: 0,
213→  };
214→
215→  workspaces.forEach((workspace) => {
216→    const status = getDisplayStatus(workspace);
217→    counts[status]++;
218→  });
219→
220→  return counts;
221→}
222→
223→/**
224→ * Get total unread count for a repository
225→ * Sums unread across all workspaces
226→ */
227→export function getRepoUnreadCount(workspaces: Workspace[]): number {
228→  return workspaces.reduce((sum, workspace) => {
229→    return sum + getUnreadCount(workspace);
230→  }, 0);
231→}
232→
233→/**
234→ * Get highest priority status for a repository
235→ * Used for collapsed sidebar badge color
236→ *
237→ * @param workspaces Workspaces in a repository
238→ * @returns The highest priority status present
239→ */
240→export function getRepoPriorityStatus(workspaces: Workspace[]): DisplayStatus {
241→  let highestPriority = StatusPriority.IDLE;
242→  let highestStatus: DisplayStatus = "idle";
243→
244→  workspaces.forEach((workspace) => {
245→    const status = getDisplayStatus(workspace);
246→    const priority = STATUS_CONFIG[status].priority;
247→
248→    if (priority > highestPriority) {
249→      highestPriority = priority;
250→      highestStatus = status;
251→    }
252→  });
253→
254→  return highestStatus;
255→}
256→

  1→import React from "react";
  2→import { match } from "ts-pattern";
  3→import { Archive, Loader2 } from "lucide-react";
  4→import NumberFlow from "@number-flow/react";
  5→
  6→import { cn } from "@/shared/lib/utils";
  7→import { useWorkingDuration, formatDuration } from "@/shared/hooks";
  8→import { CircularPixelGrid } from "@/features/session/ui/CircularPixelGrid";
  9→import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
 10→import { getWorkspaceDisplayName, getWorkspaceSecondaryText } from "../lib/utils";
 11→import type { WorkspaceItemProps } from "../model/types";
 12→import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
 13→import { WorkflowStatusIcon } from "./WorkflowStatusIcon";
 14→import { WorkspaceStatusMenu } from "./WorkspaceStatusMenu";
 15→
 16→/**
 17→ * WorkspaceItem — Sidebar workspace row
 18→ *
 19→ * Layout:  [Left (flex-1)]  [Right]
 20→ *   Left:
 21→ *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 22→ *     Row 2: [pad-left 26px] [secondary · status]
 23→ *   Right:
 24→ *     [+additions -deletions]
 25→ *
 26→ * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 27→ * Secondary line: shows slug when title is primary, otherwise just status info.
 28→ *
 29→ * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 30→ * Idle → no icon (26px indent).
 31→ *
 32→ * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 33→ */
 34→export const WorkspaceItem = React.memo(function WorkspaceItem({
 35→  workspace,
 36→  isActive,
 37→  diffStats,
 38→  onClick,
 39→  onArchive,
 40→  onStatusChange,
 41→}: WorkspaceItemProps) {
 42→  const isInitializing = workspace.state === "initializing";
 43→
 44→  // Hooks must be called unconditionally (React rules of hooks)
 45→  const { duration } = useWorkingDuration({
 46→    status: workspace.session_status,
 47→    latestMessageSentAt: workspace.latest_message_sent_at,
 48→  });
 49→
 50→  // Initializing state: non-interactive row with loading animation
 51→  if (isInitializing) {
 52→    const initSecondary = getWorkspaceSecondaryText(workspace);
 53→    return (
 54→      <div className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 55→        <SidebarRow
 56→          variant="workspace"
 57→          isActive={false}
 58→          aria-label="Workspace setting up"
 59→          className="pointer-events-none"
 60→        >
 61→          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
 62→            {/* Row 1: thinking icon + display name */}
 63→            <div className="flex min-w-0 items-center gap-1.5">
 64→              <SidebarRowIconSlot>
 65→                <CircularPixelGrid variant="working" size={14} resolution={8} />
 66→              </SidebarRowIconSlot>
 67→              <span className="text-text-disabled truncate text-base font-normal">
 68→                {getWorkspaceDisplayName(workspace)}
 69→              </span>
 70→            </div>
 71→            {/* Row 2: secondary context · init stage */}
 72→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 73→              {initSecondary && (
 74→                <>
 75→                  <span className="text-text-disabled truncate text-xs">{initSecondary}</span>
 76→                  <span className="text-text-disabled text-xs">·</span>
 77→                </>
 78→              )}
 79→              <span className="text-text-muted shrink-0 text-xs">
 80→                {match(workspace.init_stage)
 81→                  .with("worktree", () => "Creating worktree...")
 82→                  .with("dependencies", () => "Installing dependencies...")
 83→                  .with("hooks", () => "Setting up environment...")
 84→                  .with("session", () => "Finalizing...")
 85→                  .otherwise(() => "Setting up...")}
 86→              </span>
 87→            </div>
 88→          </div>
 89→        </SidebarRow>
 90→      </div>
 91→    );
 92→  }
 93→
 94→  const formatTime = (timestamp: string) => {
 95→    const date = new Date(timestamp);
 96→    const now = new Date();
 97→    const diffMs = now.getTime() - date.getTime();
 98→    const diffMins = Math.floor(diffMs / 60000);
 99→    const diffHours = Math.floor(diffMins / 60);
100→    const diffDays = Math.floor(diffHours / 24);
101→    const diffMonths = Math.floor(diffDays / 30);
102→
103→    if (diffMins < 1) return "now";
104→    if (diffMins < 60) return `${diffMins}m ago`;
105→    if (diffHours < 24) return `${diffHours}h ago`;
106→    if (diffDays < 30) return `${diffDays}d ago`;
107→    return `${diffMonths}mo ago`;
108→  };
109→
110→  const displayStatus = getDisplayStatus(workspace);
111→  const statusConfig = STATUS_CONFIG[displayStatus];
112→  // Session activity icons take priority over workflow status
113→  const hasSessionIcon =
114→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
115→
116→  const isSetupRunning = workspace.setup_status === "running";
117→  const isSetupFailed = workspace.setup_status === "failed";
118→
119→  const statusTextClass = isSetupFailed
120→    ? "text-accent-red-muted"
121→    : isSetupRunning
122→      ? "text-text-muted"
123→      : match(displayStatus)
124→          .with("working", () => "text-text-tertiary")
125→          .with("unread", () => "text-text-secondary")
126→          .with("error", () => "text-accent-red-muted")
127→          .otherwise(() => "text-text-disabled");
128→
129→  const getStatusText = (): string => {
130→    if (isSetupRunning) return "Installing...";
131→    if (isSetupFailed) return "Setup failed";
132→    if (workspace.state === "archived") return "Archived";
133→    if (!workspace.session_status) return formatTime(workspace.updated_at);
134→
135→    return match(displayStatus)
136→      .with("idle", () => formatTime(workspace.updated_at))
137→      .with("unread", () => "Needs response")
138→      .with("working", () =>
139→        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
140→      )
141→      .with("error", () => STATUS_CONFIG.error.label)
142→      .otherwise(() => statusConfig.label);
143→  };
144→
145→  const statusText = getStatusText();
146→  const displayName = getWorkspaceDisplayName(workspace);
147→  const secondaryText = getWorkspaceSecondaryText(workspace);
148→  const showStatusDot = Boolean(secondaryText && statusText);
149→
150→  const additions = diffStats?.additions ?? 0;
151→  const deletions = diffStats?.deletions ?? 0;
152→  const hasChanges = additions > 0 || deletions > 0;
153→
154→  const handleArchive = (e: React.MouseEvent) => {
155→    e.stopPropagation();
156→    if (onArchive) {
157→      onArchive(workspace.id);
158→    }
159→  };
160→
161→  const isArchived = workspace.state === "archived";
162→  const canArchive = !isArchived && !!onArchive;
163→  const isActiveState =
164→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
165→
166→  return (
167→    <div>
168→      <SidebarRow
169→        variant="workspace"
170→        isActive={isActive}
171→        role="button"
172→        tabIndex={0}
173→        data-workspace-id={workspace.id}
174→        className="cursor-pointer"
175→        aria-current={isActive ? "page" : undefined}
176→        aria-label={`Workspace ${displayName}`}
177→        onClick={() => onClick(workspace)}
178→        onKeyDown={(e) => {
179→          if (e.key === " ") e.preventDefault();
180→        }}
181→        onKeyUp={(e) => {
182→          if (e.key === "Enter" || e.key === " ") onClick(workspace);
183→        }}
184→      >
185→        {/* Left: rows */}
186→        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
187→          {/* Row 1: icon + display name (title > slug > branch) */}
188→          <div className="flex min-w-0 items-center gap-1.5">
189→            <WorkspaceStatusMenu
190→              currentStatus={workspace.status}
191→              onStatusChange={(status) => onStatusChange?.(workspace.id, status)}
192→            >
193→              <button
194→                type="button"
195→                onClick={(e) => e.stopPropagation()}
196→                className="flex h-5 w-5 shrink-0 items-center justify-center rounded transition-opacity hover:opacity-80"
197→                aria-label={`Status: ${workspace.status}`}
198→              >
199→                {hasSessionIcon ? (
200→                  match(displayStatus)
201→                    .with("working", () => (
202→                      <CircularPixelGrid variant="working" size={14} resolution={8} />
203→                    ))
204→                    .with("error", () => <span className="bg-accent-red h-2 w-2 rounded-full" />)
205→                    .otherwise(() => <span className="bg-accent-gold h-2 w-2 rounded-full" />)
206→                ) : (
207→                  <WorkflowStatusIcon status={workspace.status} size={14} />
208→                )}
209→              </button>
210→            </WorkspaceStatusMenu>
211→            <span
212→              className={cn(
213→                "truncate text-base",
214→                isActive
215→                  ? "text-text-primary font-medium"
216→                  : isActiveState
217→                    ? "text-text-primary font-normal"
218→                    : "text-text-tertiary font-normal"
219→              )}
220→            >
221→              {displayName}
222→            </span>
223→          </div>
224→
225→          {/* Row 2: secondary context · status */}
226→          <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
227→            {secondaryText && (
228→              <span
229→                className={cn(
230→                  "truncate text-xs",
231→                  isActiveState ? "text-text-tertiary" : "text-text-disabled"
232→                )}
233→              >
234→                {secondaryText}
235→              </span>
236→            )}
237→            {showStatusDot && (
238→              <span
239→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
240→              >
241→                ·
242→              </span>
243→            )}
244→            {statusText && (
245→              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
246→                {isSetupRunning && (
247→                  <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />
248→                )}
249→                {statusText}
250→              </span>
251→            )}
252→          </div>
253→        </div>
254→
255→        {/* Right: diff stats */}
256→        {hasChanges ? (
257→          <div
258→            className={cn(
259→              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
260→              canArchive && "group-hover/sidebar-row:opacity-0"
261→            )}
262→          >
263→            {additions > 0 && (
264→              <NumberFlow
265→                value={additions}
266→                prefix="+"
267→                className={isActive ? "text-accent-green" : "text-text-muted"}
268→              />
269→            )}
270→            {deletions > 0 && (
271→              <NumberFlow
272→                value={deletions}
273→                prefix="-"
274→                className={isActive ? "text-accent-red" : "text-text-muted"}
275→              />
276→            )}
277→          </div>
278→        ) : null}
279→
280→        {/* Archive button — hover reveal */}
281→        {canArchive ? (
282→          <button
283→            type="button"
284→            onClick={handleArchive}
285→            aria-label={`Archive workspace ${displayName}`}
286→            title="Archive workspace"
287→            className={cn(
288→              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
289→              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
290→              "group-hover/sidebar-row:opacity-100"
291→            )}
292→          >
293→            <Archive className="h-3.5 w-3.5" />
294→          </button>
295→        ) : null}
296→      </SidebarRow>
297→    </div>
298→  );
299→});
300→

  1→/**
  2→ * Global Session Notifications
  3→ *
  4→ * Sends OS-level notifications when the app is in the background.
  5→ *
  6→ * Notification triggers:
  7→ * - Agent finished working (working → idle)                → Glass sound
  8→ * - Agent error (→ error with error_category)              → Basso sound
  9→ * - Agent needs input (→ needs_response)                   → Ping sound
 10→ * - Plan ready for review (→ needs_plan_response)          → Ping sound
 11→ * - Setup failed/completed                                 → Basso/Glass sound
 12→ *
 13→ * All transitions are detected by observing the workspace React Query cache,
 14→ * which is kept fresh by the WS subscription. No IPC event listeners needed.
 15→ *
 16→ * When the app is in the foreground, notifications are suppressed —
 17→ * Sonner toasts handle in-app feedback.
 18→ */
 19→
 20→import { useEffect, useRef } from "react";
 21→import { useQueryClient } from "@tanstack/react-query";
 22→import { match } from "ts-pattern";
 23→import { capabilities } from "@/platform/capabilities";
 24→import { sendNotification } from "@/platform/notifications";
 25→import { isWindowFocused } from "@/shared/hooks/useWindowFocus";
 26→import { track } from "@/platform/analytics";
 27→import type { SessionStatus } from "@shared/types/session";
 28→import type { RepoGroup, SetupStatus } from "@shared/types/workspace";
 29→
 30→/**
 31→ * Batches multiple notifications within a short window into a single one.
 32→ * Prevents notification spam when multiple agents finish simultaneously.
 33→ */
 34→const BATCH_WINDOW_MS = 1500;
 35→
 36→export function useGlobalSessionNotifications() {
 37→  const prevStatusMap = useRef(new Map<string, SessionStatus>());
 38→  const prevSetupStatusMap = useRef(new Map<string, SetupStatus>());
 39→  const finishedBatch = useRef<string[]>([]);
 40→  const batchTimerRef = useRef<ReturnType<typeof setTimeout>>();
 41→
 42→  const queryClient = useQueryClient();
 43→
 44→  useEffect(() => {
 45→    if (!capabilities.nativeNotifications) return;
 46→
 47→    function flushFinishedBatch() {
 48→      const batch = finishedBatch.current;
 49→      finishedBatch.current = [];
 50→      batchTimerRef.current = undefined;
 51→
 52→      if (batch.length === 0 || isWindowFocused()) return;
 53→
 54→      if (batch.length === 1) {
 55→        sendNotification({
 56→          title: "Agent finished",
 57→          body: `Session ${batch[0].substring(0, 8)} completed`,
 58→          sound: "Glass",
 59→        });
 60→      } else {
 61→        sendNotification({
 62→          title: `${batch.length} agents finished`,
 63→          body: "Multiple sessions completed",
 64→          sound: "Glass",
 65→        });
 66→      }
 67→    }
 68→
 69→    function queueFinished(sessionId: string) {
 70→      finishedBatch.current.push(sessionId);
 71→      if (!batchTimerRef.current) {
 72→        batchTimerRef.current = setTimeout(flushFinishedBatch, BATCH_WINDOW_MS);
 73→      }
 74→    }
 75→
 76→    // Detect all session + setup transitions from the workspace cache.
 77→    // The WS subscription pushes updated workspace rows including
 78→    // session_status, session_error_category, and session_error_message.
 79→    const unsubscribe = queryClient.getQueryCache().subscribe((event) => {
 80→      if (event.type !== "updated" || !event.query.queryKey[0]) return;
 81→
 82→      const key = event.query.queryKey;
 83→      if (key[0] !== "workspaces" || key[1] !== "by-repo") return;
 84→
 85→      const groups = event.query.state.data as RepoGroup[] | undefined;
 86→      if (!groups) return;
 87→
 88→      for (const group of groups) {
 89→        for (const ws of group.workspaces) {
 90→          // --- Session status transitions ---
 91→          if (ws.current_session_id && ws.session_status) {
 92→            const sessionId = ws.current_session_id;
 93→            const status = ws.session_status as SessionStatus;
 94→            const prevStatus = prevStatusMap.current.get(sessionId);
 95→            prevStatusMap.current.set(sessionId, status);
 96→
 97→            if (prevStatus && prevStatus !== status) {
 98→              // working → idle = agent finished
 99→              if (prevStatus === "working" && status === "idle") {
100→                track("ai_turn_completed", { session_id: sessionId });
101→                if (!isWindowFocused()) queueFinished(sessionId);
102→              }
103→
104→              // → needs_response = agent needs user input
105→              if (status === "needs_response" && !isWindowFocused()) {
106→                sendNotification({
107→                  title: "Agent needs input",
108→                  body: `Session ${sessionId.substring(0, 8)} is waiting for your response`,
109→                  sound: "Ping",
110→                });
111→              }
112→
113→              // → needs_plan_response = plan ready for review
114→              if (status === "needs_plan_response" && !isWindowFocused()) {
115→                sendNotification({
116→                  title: "Plan ready for review",
117→                  body: `Session ${sessionId.substring(0, 8)} has a plan waiting for approval`,
118→                  sound: "Ping",
119→                });
120→              }
121→
122→              // → error = agent errored (with category-aware title)
123→              if (status === "error") {
124→                const category = ws.session_error_category ?? undefined;
125→                track("session_error_displayed", {
126→                  session_id: sessionId,
127→                  error_category: category,
128→                });
129→
130→                if (!isWindowFocused()) {
131→                  const title = match(category)
132→                    .with("auth", () => "Authentication Error")
133→                    .with("rate_limit", () => "Rate Limited")
134→                    .with("context_limit", () => "Context Limit Reached")
135→                    .with("network", () => "Network Error")
136→                    .with("db_write", () => "Database Error")
137→                    .with("process_exit", () => "Agent Process Crashed")
138→                    .otherwise(() => "Agent Error");
139→                  sendNotification({
140→                    title,
141→                    body:
142→                      ws.session_error_message ||
143→                      `Session ${sessionId.substring(0, 8)} encountered an error`,
144→                    sound: "Basso",
145→                  });
146→                }
147→              }
148→            }
149→          }
150→
151→          // --- Setup status transitions ---
152→          const prevSetup = prevSetupStatusMap.current.get(ws.id);
153→          prevSetupStatusMap.current.set(ws.id, ws.setup_status);
154→
155→          if (!prevSetup) continue;
156→          if (prevSetup === ws.setup_status) continue;
157→
158→          if (
159→            prevSetup === "running" &&
160→            (ws.setup_status === "failed" || ws.setup_status === "completed")
161→          ) {
162→            track("workspace_setup_completed", {
163→              workspace_id: ws.id,
164→              setup_status: ws.setup_status,
165→            });
166→          }
167→
168→          if (prevSetup === "running" && ws.setup_status === "failed" && !isWindowFocused()) {
169→            sendNotification({
170→              title: "Setup failed",
171→              body: `Workspace ${ws.title || ws.slug} setup failed${ws.error_message ? `: ${ws.error_message}` : ""}`,
172→              sound: "Basso",
173→            });
174→          }
175→
176→          if (prevSetup === "running" && ws.setup_status === "completed") {
177→            queryClient.invalidateQueries({ queryKey: ["workspaces", "manifest", ws.id] });
178→            if (!isWindowFocused()) {
179→              sendNotification({
180→                title: "Setup complete",
181→                body: `Workspace ${ws.title || ws.slug} is ready`,
182→                sound: "Glass",
183→              });
184→            }
185→          }
186→        }
187→      }
188→    });
189→
190→    return () => {
191→      unsubscribe();
192→      if (batchTimerRef.current) clearTimeout(batchTimerRef.current);
193→    };
194→  }, [queryClient]);
195→}
