  1→import * as React from "react";
  2→import {
  3→  DndContext,
  4→  closestCenter,
  5→  KeyboardSensor,
  6→  PointerSensor,
  7→  useSensor,
  8→  useSensors,
  9→  DragEndEvent,
 10→} from "@dnd-kit/core";
 11→import {
 12→  arrayMove,
 13→  SortableContext,
 14→  sortableKeyboardCoordinates,
 15→  verticalListSortingStrategy,
 16→} from "@dnd-kit/sortable";
 17→import { FolderOpen } from "lucide-react";
 18→import { Sidebar, SidebarContent, SidebarMenu, useSidebar } from "@/components/ui/sidebar";
 19→import { useUIStore } from "@/shared/stores/uiStore";
 20→import { useSidebarStore } from "../store/sidebarStore";
 21→import type { AppSidebarProps } from "../model/types";
 22→import { DraggableRepository } from "./DraggableRepository";
 23→import { SidebarHeader } from "./SidebarHeader";
 24→import { SidebarFooter } from "./SidebarFooter";
 25→
 26→export function AppSidebar({
 27→  repositories,
 28→  selectedWorkspaceId,
 29→  onWorkspaceClick,
 30→  onNewWorkspace,
 31→  onNewWorkspaceFromGitHub,
 32→  onAddRepository,
 33→  onCloneRepository,
 34→  onArchive,
 35→  onStatusChange,
 36→  diffStatsMap,
 37→  profile = { username: "User" },
 38→}: AppSidebarProps) {
 39→  const { state, hoverOpen, toggleSidebar } = useSidebar();
 40→  const openSettings = useUIStore((s) => s.openSettings);
 41→  const collapsedRepos = useSidebarStore((s) => s.collapsedRepos);
 42→  const toggleRepoCollapse = useSidebarStore((s) => s.toggleRepoCollapse);
 43→  const repositoryOrder = useSidebarStore((s) => s.repositoryOrder);
 44→  const setRepositoryOrder = useSidebarStore((s) => s.setRepositoryOrder);
 45→  const reorderRepositories = useSidebarStore((s) => s.reorderRepositories);
 46→
 47→  const isExpanded = state === "expanded" || hoverOpen;
 48→
 49→  // User's drag-drop order is the final word.
 50→  // Status is shown visually (badges, colors) — not by re-sorting after drag.
 51→  const orderedRepositories = React.useMemo(
 52→    () => reorderRepositories(repositories),
 53→    [repositories, repositoryOrder, reorderRepositories]
 54→  );
 55→
 56→  // 5px distance threshold: click = expand/collapse, drag = reorder
 57→  const sensors = useSensors(
 58→    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
 59→    useSensor(KeyboardSensor, {
 60→      coordinateGetter: sortableKeyboardCoordinates,
 61→    })
 62→  );
 63→
 64→  /**
 65→   * Handle drag end - reorder repositories
 66→   */
 67→  function handleDragEnd(event: DragEndEvent) {
 68→    const { active, over } = event;
 69→
 70→    if (!over || active.id === over.id) {
 71→      return;
 72→    }
 73→
 74→    const oldIndex = orderedRepositories.findIndex((r) => r.repo_id === active.id);
 75→    const newIndex = orderedRepositories.findIndex((r) => r.repo_id === over.id);
 76→
 77→    if (oldIndex === -1 || newIndex === -1) {
 78→      return;
 79→    }
 80→
 81→    // Reorder array
 82→    const reordered = arrayMove(orderedRepositories, oldIndex, newIndex);
 83→
 84→    // Save new order to store
 85→    const newOrder = reordered.map((r) => r.repo_id);
 86→    setRepositoryOrder(newOrder);
 87→  }
 88→
 89→  return (
 90→    <Sidebar variant="inset" collapsible="offcanvas" className="p-0">
 91→      <SidebarHeader
 92→        profile={profile}
 93→        onOpenSettings={openSettings}
 94→        onToggleSidebar={toggleSidebar}
 95→        isExpanded={isExpanded}
 96→      />
 97→
 98→      {/* Repositories List or Empty State */}
 99→      {repositories.length === 0 ? (
100→        <SidebarContent className="flex h-full items-center justify-center">
101→          <div className="flex flex-col items-center gap-3 px-6 text-center">
102→            <FolderOpen className="text-text-muted/30 h-10 w-10" strokeWidth={1.5} />
103→            <div className="space-y-1">
104→              <p className="text-text-secondary text-sm font-medium">No projects yet</p>
105→              <p className="text-text-muted text-xs">Add your first project to get started</p>
106→            </div>
107→          </div>
108→        </SidebarContent>
109→      ) : (
110→        <SidebarContent className="scrollbar-hidden">
111→          <DndContext
112→            sensors={sensors}
113→            collisionDetection={closestCenter}
114→            onDragEnd={handleDragEnd}
115→          >
116→            <SortableContext
117→              items={orderedRepositories.map((r) => r.repo_id)}
118→              strategy={verticalListSortingStrategy}
119→            >
120→              <SidebarMenu className="gap-1 px-1.5 py-2">
121→                {orderedRepositories.map((repo) => (
122→                  <DraggableRepository
123→                    key={repo.repo_id}
124→                    repository={repo}
125→                    isCollapsed={collapsedRepos.has(repo.repo_id)}
126→                    selectedWorkspaceId={selectedWorkspaceId}
127→                    onToggleCollapse={() => toggleRepoCollapse(repo.repo_id)}
128→                    onWorkspaceClick={onWorkspaceClick}
129→                    onNewWorkspace={onNewWorkspace}
130→                    onNewWorkspaceFromGitHub={onNewWorkspaceFromGitHub}
131→                    onArchive={onArchive}
132→                    onStatusChange={onStatusChange}
133→                    diffStatsMap={diffStatsMap}
134→                    sidebarExpanded={isExpanded}
135→                    dragDisabled={!isExpanded}
136→                  />
137→                ))}
138→              </SidebarMenu>
139→            </SortableContext>
140→          </DndContext>
141→        </SidebarContent>
142→      )}
143→
144→      <SidebarFooter onAddRepository={onAddRepository} onCloneRepository={onCloneRepository} />
145→    </Sidebar>
146→  );
147→}
