  1→// backend/src/services/agent/event-handler.ts
  2→// Receives canonical AgentEvent notifications from the agent-client and
  3→// dispatches them to persistence (DB writes) and WS push (query invalidation).
  4→//
  5→// This is the single entry point for all agent → backend data flow.
  6→// Each event is handled: persist first, then invalidate (ordering matters).
  7→//
  8→// Created via createAgentEventHandler() — a factory that injects the
  9→// respondToAgent dependency, breaking the circular import with service.ts.
 10→
 11→import { match } from "ts-pattern";
 12→import type { AgentEvent } from "@shared/agent-events";
 13→import type { QueryResource } from "@shared/types/query-protocol";
 14→import { invalidate } from "../query-engine";
 15→import { relay } from "./tool-relay";
 16→import {
 17→  persistAssistantMessage,
 18→  persistToolResultMessage,
 19→  persistMessageResult,
 20→  persistMessageCancelled,
 21→  persistSessionStarted,
 22→  persistSessionIdle,
 23→  persistSessionError,
 24→  persistSessionCancelled,
 25→  persistAgentSessionId,
 26→  persistSessionTitle,
 27→  type WriteResult,
 28→} from "./persistence";
 29→
 30→// ---- Types ----
 31→
 32→type RespondToAgentFn = (params: {
 33→  sessionId: string;
 34→  requestId: string;
 35→  result: unknown;
 36→}) => Promise<void>;
 37→
 38→export type AgentEventHandler = (event: AgentEvent) => void;
 39→
 40→// ---- Resource groups for invalidation ----
 41→
 42→const SESSION_RESOURCES: QueryResource[] = ["workspaces", "sessions", "session", "stats"];
 43→const MESSAGE_RESOURCES: QueryResource[] = ["messages", "session"];
 44→
 45→// ---- Helpers ----
 46→
 47→/** Persist an event and invalidate subscriptions if the write succeeded. */
 48→function persistAndInvalidate(
 49→  result: WriteResult<unknown>,
 50→  resources: QueryResource[],
 51→  sessionId: string
 52→): void {
 53→  if (result.ok) {
 54→    invalidate(resources, { sessionIds: [sessionId] });
 55→  }
 56→}
 57→
 58→// ---- Factory ----
 59→
 60→/**
 61→ * Create an agent event handler with injected dependencies.
 62→ *
 63→ * The respondToAgent function is injected to break the circular dependency
 64→ * between this module and service.ts. The composition root (service.ts)
 65→ * provides the concrete implementation: client.sendTurnRespond().
 66→ */
 67→export function createAgentEventHandler(deps: {
 68→  respondToAgent: RespondToAgentFn;
 69→}): AgentEventHandler {
 70→  const { respondToAgent } = deps;
 71→
 72→  return function handleAgentEvent(event: AgentEvent): void {
 73→    match(event)
 74→      // ── Session lifecycle ─────────────────────────────────────────────
 75→      .with({ type: "session.started" }, (e) => {
 76→        console.log(`[AgentEvent] session.started: session=${e.sessionId} agent=${e.agentType}`);
 77→        persistAndInvalidate(persistSessionStarted(e), SESSION_RESOURCES, e.sessionId);
 78→      })
 79→      .with({ type: "session.idle" }, (e) => {
 80→        console.log(`[AgentEvent] session.idle: session=${e.sessionId}`);
 81→        persistAndInvalidate(persistSessionIdle(e), SESSION_RESOURCES, e.sessionId);
 82→      })
 83→      .with({ type: "session.error" }, (e) => {
 84→        console.log(`[AgentEvent] session.error: session=${e.sessionId} error=${e.error}`);
 85→        persistAndInvalidate(persistSessionError(e), SESSION_RESOURCES, e.sessionId);
 86→      })
 87→      .with({ type: "session.cancelled" }, (e) => {
 88→        console.log(`[AgentEvent] session.cancelled: session=${e.sessionId}`);
 89→        persistAndInvalidate(persistSessionCancelled(e), SESSION_RESOURCES, e.sessionId);
 90→      })
 91→
 92→      // ── Messages ──────────────────────────────────────────────────────
 93→      .with({ type: "message.assistant" }, (e) => {
 94→        console.log(`[AgentEvent] message.assistant: session=${e.sessionId} msgId=${e.message.id}`);
 95→        persistAndInvalidate(persistAssistantMessage(e), MESSAGE_RESOURCES, e.sessionId);
 96→      })
 97→      .with({ type: "message.tool_result" }, (e) => {
 98→        console.log(
 99→          `[AgentEvent] message.tool_result: session=${e.sessionId} msgId=${e.message.id}`
100→        );
101→        persistAndInvalidate(persistToolResultMessage(e), MESSAGE_RESOURCES, e.sessionId);
102→      })
103→      .with({ type: "message.result" }, (e) => {
104→        console.log(`[AgentEvent] message.result: session=${e.sessionId} subtype=${e.subtype}`);
105→        persistMessageResult(e);
106→      })
107→      .with({ type: "message.cancelled" }, (e) => {
108→        console.log(`[AgentEvent] message.cancelled: session=${e.sessionId}`);
109→        persistAndInvalidate(
110→          persistMessageCancelled(e),
111→          ["messages", "sessions", "session", "stats"],
112→          e.sessionId
113→        );
114→      })
115→
116→      // ── Interaction requests ──────────────────────────────────────────
117→      .with({ type: "request.opened" }, (e) => {
118→        console.log(
119→          `[AgentEvent] request.opened: session=${e.sessionId} requestId=${e.requestId} type=${e.requestType}`
120→        );
121→      })
122→      .with({ type: "request.resolved" }, (e) => {
123→        console.log(
124→          `[AgentEvent] request.resolved: session=${e.sessionId} requestId=${e.requestId}`
125→        );
126→      })
127→
128→      // ── Tool relay ────────────────────────────────────────────────────
129→      .with({ type: "tool.request" }, (e) => {
130→        console.log(
131→          `[AgentEvent] tool.request: session=${e.sessionId} method=${e.method} requestId=${e.requestId}`
132→        );
133→        void relayToolRequest(e, respondToAgent);
134→      })
135→
136→      // ── Metadata ──────────────────────────────────────────────────────
137→      .with({ type: "agent.session_id" }, (e) => {
138→        console.log(
139→          `[AgentEvent] agent.session_id: session=${e.sessionId} agentSessionId=${e.agentSessionId}`
140→        );
141→        persistAndInvalidate(persistAgentSessionId(e), SESSION_RESOURCES, e.sessionId);
142→      })
143→      .with({ type: "session.title" }, (e) => {
144→        console.log(`[AgentEvent] session.title: session=${e.sessionId} title="${e.title}"`);
145→        persistAndInvalidate(persistSessionTitle(e), SESSION_RESOURCES, e.sessionId);
146→      })
147→
148→      .exhaustive();
149→  };
150→}
151→
152→// ---- Tool relay internal ----
153→
154→async function relayToolRequest(
155→  event: AgentEvent & { type: "tool.request" },
156→  respondToAgent: RespondToAgentFn
157→): Promise<void> {
158→  const { sessionId, requestId, method } = event;
159→
160→  try {
161→    const result = await relay(event);
162→    await respondToAgent({ sessionId, requestId, result });
163→    console.log(`[AgentEvent] tool.request resolved: requestId=${requestId} method=${method}`);
164→  } catch (err) {
165→    console.error(`[AgentEvent] tool.request failed: requestId=${requestId} method=${method}`, err);
166→    try {
167→      await respondToAgent({
168→        sessionId,
169→        requestId,
170→        result: { error: err instanceof Error ? err.message : "Tool relay failed" },
171→      });
172→    } catch (respondErr) {
173→      console.error(
174→        `[AgentEvent] Failed to send error response to agent: requestId=${requestId}`,
175→        respondErr
176→      );
177→    }
178→  }
179→}
180→

  1→// backend/src/services/agent/persistence.ts
  2→// Database write functions for persisting canonical agent events.
  3→//
  4→// Adapted from sidecar/db/session-writer.ts. Key differences:
  5→// - Uses backend's getDatabase() (not sidecar's)
  6→// - No notifyBackend() calls (backend handles WS push via invalidate())
  7→// - No FrontendClient calls (backend pushes via query-engine directly)
  8→// - Takes event objects instead of positional args
  9→//
 10→// All functions are synchronous (better-sqlite3 is synchronous).
 11→// Callers (event-handler.ts) call invalidate() after persistence succeeds.
 12→
 13→import { getDatabase } from "../../lib/database";
 14→import { uuidv7 } from "@shared/lib/uuid";
 15→import { getErrorMessage } from "@shared/lib/errors";
 16→import type {
 17→  MessageAssistantEvent,
 18→  MessageToolResultEvent,
 19→  MessageResultEvent,
 20→  MessageCancelledEvent,
 21→  SessionStartedEvent,
 22→  SessionIdleEvent,
 23→  SessionErrorEvent,
 24→  SessionCancelledEvent,
 25→  AgentSessionIdEvent,
 26→  SessionTitleEvent,
 27→} from "@shared/agent-events";
 28→
 29→// ============================================================================
 30→// WriteResult type (mirrors sidecar's pattern)
 31→// ============================================================================
 32→
 33→export type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 34→
 35→// ============================================================================
 36→// Message writes
 37→// ============================================================================
 38→
 39→/**
 40→ * Save an assistant message to the messages table.
 41→ * Mirrors sidecar saveAssistantMessage() logic:
 42→ * - Generates a local UUID7 message ID
 43→ * - Stores flat content array, except for cancelled messages which get an envelope
 44→ * - Records the agent_message_id and parent_tool_use_id for linking
 45→ */
 46→export function persistAssistantMessage(event: MessageAssistantEvent): WriteResult {
 47→  const db = getDatabase();
 48→  const messageId = uuidv7();
 49→  const sentAt = new Date().toISOString();
 50→
 51→  // Store flat content array for normal messages. For "cancelled" messages,
 52→  // write envelope so the frontend can detect cancellation from DB content.
 53→  const contentPayload =
 54→    event.message.stop_reason === "cancelled"
 55→      ? { message: { stop_reason: "cancelled" }, blocks: event.message.content ?? [] }
 56→      : (event.message.content ?? []);
 57→  const content = JSON.stringify(contentPayload);
 58→
 59→  try {
 60→    db.prepare(
 61→      `INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 62→       VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)`
 63→    ).run(
 64→      messageId,
 65→      event.sessionId,
 66→      content,
 67→      sentAt,
 68→      event.model || null,
 69→      event.message.id || null,
 70→      event.message.parent_tool_use_id || null
 71→    );
 72→    return { ok: true, value: messageId };
 73→  } catch (error) {
 74→    const msg = getErrorMessage(error);
 75→    console.error(`[AgentPersistence] Failed to save assistant message:`, msg);
 76→    return { ok: false, error: msg };
 77→  }
 78→}
 79→
 80→/**
 81→ * Save a tool_result message (role='user') to the messages table.
 82→ * These contain tool execution results that link tool_use blocks to their outputs.
 83→ */
 84→export function persistToolResultMessage(event: MessageToolResultEvent): WriteResult {
 85→  const db = getDatabase();
 86→  const messageId = uuidv7();
 87→  const sentAt = new Date().toISOString();
 88→  const content = JSON.stringify(event.message.content ?? []);
 89→
 90→  try {
 91→    db.prepare(
 92→      `INSERT INTO messages (id, session_id, role, content, sent_at, agent_message_id, parent_tool_use_id)
 93→       VALUES (?, ?, 'user', ?, ?, ?, ?)`
 94→    ).run(
 95→      messageId,
 96→      event.sessionId,
 97→      content,
 98→      sentAt,
 99→      event.message.id || null,
100→      event.message.parent_tool_use_id || null
101→    );
102→    return { ok: true, value: messageId };
103→  } catch (error) {
104→    const msg = getErrorMessage(error);
105→    console.error(`[AgentPersistence] Failed to save tool_result message:`, msg);
106→    return { ok: false, error: msg };
107→  }
108→}
109→
110→/**
111→ * Handle message.result events. No DB write needed — this is informational
112→ * (success/error_during_execution subtypes). Session status transitions are
113→ * handled by separate session.idle / session.error events.
114→ */
115→export function persistMessageResult(_event: MessageResultEvent): void {
116→  // No-op: message.result is informational only.
117→  // Session status is managed by session.idle / session.error events.
118→}
119→
120→/**
121→ * Persist a cancellation: insert a cancelled assistant message marker
122→ * and set session status to idle.
123→ *
124→ * The cancelled message uses the envelope format so the frontend can detect
125→ * cancellation on reload (the "Turn interrupted" label in AssistantTurn).
126→ */
127→export function persistMessageCancelled(event: MessageCancelledEvent): WriteResult {
128→  const db = getDatabase();
129→  const messageId = uuidv7();
130→  const sentAt = new Date().toISOString();
131→
132→  // Empty cancelled message with envelope so frontend detects cancellation
133→  const content = JSON.stringify({
134→    message: { stop_reason: "cancelled" },
135→    blocks: [],
136→  });
137→
138→  try {
139→    db.transaction(() => {
140→      db.prepare(
141→        `INSERT INTO messages (id, session_id, role, content, sent_at, cancelled_at)
142→         VALUES (?, ?, 'assistant', ?, ?, ?)`
143→      ).run(messageId, event.sessionId, content, sentAt, sentAt);
144→
145→      db.prepare(
146→        `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
147→      ).run(event.sessionId);
148→    })();
149→
150→    return { ok: true, value: messageId };
151→  } catch (error) {
152→    const msg = getErrorMessage(error);
153→    console.error(`[AgentPersistence] Failed to persist message.cancelled:`, msg);
154→    return { ok: false, error: msg };
155→  }
156→}
