285→  const db = getDatabase();
286→
287→  try {
288→    db.prepare(
289→      `UPDATE sessions SET agent_session_id = ?, updated_at = datetime('now') WHERE id = ?`
290→    ).run(event.agentSessionId, event.sessionId);
291→    return { ok: true, value: undefined };
292→  } catch (error) {
293→    const msg = getErrorMessage(error);
294→    console.error(`[AgentPersistence] Failed to persist agent.session_id:`, msg);
295→    return { ok: false, error: msg };
296→  }
297→}
