17→export function SortableTab({ id, children, className }: SortableTabProps) {
18→  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
19→    id,
20→    // Snappy spring-like transition for neighbors shifting (ease-out-quart 200ms)
