29→    transform: CSS.Translate.toString(transform ? { ...transform, y: 0 } : null),
30→    transition,
31→  };
32→
33→  return (
34→    <div
35→      ref={setNodeRef}
36→      style={style}
37→      {...attributes}
38→      {...listeners}
39→      className={cn(isDragging && "z-50 opacity-50", className)}
40→    >
41→      {children}
42→    </div>
43→  );
