  1→/**
  2→ * useChatTabs — manages chat tab lifecycle with persistence across workspace switches.
  3→ *
  4→ * Tab order and active tab are persisted in workspaceLayoutStore (localStorage).
  5→ * Full tab metadata (agentType, hasStarted, label) is reconstructed from session
  6→ * records fetched via useWorkspaceSessions.
  7→ */
  8→
  9→import { useState, useEffect, useRef, useCallback, useMemo } from "react";
 10→import { toast } from "sonner";
 11→import { useCreateSession, useWorkspaceSessions } from "@/features/session/api/session.queries";
 12→import {
 13→  getRuntimeAgentLabel,
 14→  getRuntimeAgentTypeForModel,
 15→  type RuntimeAgentType,
 16→} from "@/features/session/lib/agentRuntime";
 17→import { workspaceLayoutActions } from "@/features/workspace/store/workspaceLayoutStore";
 18→import type { Tab, ClosedTab } from "@/features/workspace/ui/MainContentTabs";
 19→import type { Session } from "@/features/session/types";
 20→
 21→const NEW_CHAT_LABEL = "New chat";
 22→const MAX_CLOSED_TABS = 20;
 23→
 24→function buildStartedChatLabel(agentType: string, sequence: number): string {
 25→  return `${getRuntimeAgentLabel(agentType)} #${sequence}`;
 26→}
 27→
 28→/** Build a Tab from a session record. Sequence is computed externally. */
 29→function sessionToTab(session: Session, sequence: number): Tab {
 30→  const hasStarted = session.message_count > 0;
 31→  const agentType = session.agent_type || "claude";
 32→  return {
 33→    id: `tab-${session.id}`,
 34→    label: hasStarted ? buildStartedChatLabel(agentType, sequence) : NEW_CHAT_LABEL,
 35→    data: {
 36→      sessionId: session.id,
 37→      agentType,
 38→      hasStarted,
 39→    },
 40→  };
 41→}
 42→
 43→/** Count started tabs of a given agent type, excluding a specific tab. */
 44→function countStartedTabsOfType(tabs: Tab[], agentType: string, excludeTabId: string): number {
 45→  return tabs.filter(
 46→    (t) => t.id !== excludeTabId && t.data?.hasStarted && t.data?.agentType === agentType
 47→  ).length;
 48→}
 49→
 50→/** Compute per-agent-type sequence numbers for a list of sessions (in order). */
 51→function computeSequences(sessions: Session[]): Map<string, number> {
 52→  const counters = new Map<string, number>();
 53→  const result = new Map<string, number>();
 54→  for (const s of sessions) {
 55→    if (s.message_count > 0) {
 56→      const at = s.agent_type || "claude";
 57→      const next = (counters.get(at) ?? 0) + 1;
 58→      counters.set(at, next);
 59→      result.set(s.id, next);
 60→    }
 61→  }
 62→  return result;
 63→}
 64→
 65→interface UseChatTabsOptions {
 66→  workspaceId: string;
 67→  activeSessionId: string | null | undefined;
 68→}
 69→
 70→export function useChatTabs({ workspaceId, activeSessionId }: UseChatTabsOptions) {
 71→  // Fetch all sessions for this workspace (for hydrating tab metadata)
 72→  const { data: workspaceSessions } = useWorkspaceSessions(workspaceId);
 73→
 74→  // Build session lookup map
 75→  const sessionMap = useMemo(() => {
 76→    const map = new Map<string, Session>();
 77→    if (workspaceSessions) {
 78→      for (const s of workspaceSessions) map.set(s.id, s);
 79→    }
 80→    return map;
 81→  }, [workspaceSessions]);
 82→
 83→  // --- Hydrate initial state from localStorage + session data ---
 84→
 85→  const [mainTabs, setMainTabs] = useState<Tab[]>(() => {
 86→    const layout = workspaceLayoutActions.getLayout(workspaceId);
 87→    const persistedIds = layout.chatTabSessionIds;
 88→
 89→    if (persistedIds.length === 0) {
 90→      // First mount or migration — single tab with workspace's active session
 91→      return [
 92→        {
 93→          id: activeSessionId ? `tab-${activeSessionId}` : "tab-default",
 94→          label: NEW_CHAT_LABEL,
 95→          data: {
 96→            sessionId: activeSessionId ?? undefined,
 97→            agentType: "claude",
 98→            hasStarted: false,
 99→          },
100→        },
101→      ];
102→    }
103→
104→    // Create placeholder tabs from persisted IDs (synchronous, instant)
105→    return persistedIds.map((sessionId) => ({
106→      id: `tab-${sessionId}`,
107→      label: NEW_CHAT_LABEL,
108→      data: {
109→        sessionId,
110→        agentType: "claude",
111→        hasStarted: false,
112→      },
113→    }));
114→  });
115→
116→  const [activeMainTabId, setActiveMainTabId] = useState<string>(() => {
117→    const layout = workspaceLayoutActions.getLayout(workspaceId);
118→    if (layout.activeChatTabSessionId) {
119→      return `tab-${layout.activeChatTabSessionId}`;
120→    }
121→    return activeSessionId ? `tab-${activeSessionId}` : "tab-default";
122→  });
123→
124→  const [closedTabs, setClosedTabs] = useState<ClosedTab[]>([]);
125→
126→  const createSessionMutation = useCreateSession();
127→
128→  // --- Patch default tab when workspace init completes ---
129→  // When a workspace transitions from initializing → ready, activeSessionId
130→  // goes from null to a UUID. Update the placeholder "tab-default" in-place
131→  // so ChatArea can render SessionPanel without a full remount.
132→  const prevActiveSessionIdRef = useRef(activeSessionId);
133→  useEffect(() => {
134→    const prev = prevActiveSessionIdRef.current;
135→    prevActiveSessionIdRef.current = activeSessionId;
136→
137→    // Only act when transitioning from null/undefined → real session ID
138→    if (prev || !activeSessionId) return;
139→
140→    setMainTabs((tabs) => {
141→      const defaultIdx = tabs.findIndex((t) => t.id === "tab-default");
142→      if (defaultIdx === -1) return tabs;
143→
144→      const updated = [...tabs];
145→      updated[defaultIdx] = {
146→        ...updated[defaultIdx],
147→        id: `tab-${activeSessionId}`,
148→        data: {
149→          ...updated[defaultIdx].data,
150→          sessionId: activeSessionId,
151→        },
152→      };
153→      return updated;
154→    });
155→
156→    setActiveMainTabId((prev) => (prev === "tab-default" ? `tab-${activeSessionId}` : prev));
157→  }, [activeSessionId]);
158→
159→  // --- Hydrate tabs with real session data when sessions load ---
160→
161→  const hydrated = useRef(false);
162→  useEffect(() => {
163→    if (!workspaceSessions || hydrated.current) return;
164→    hydrated.current = true;
165→
166→    // eslint-disable-next-line react-hooks/set-state-in-effect -- one-time hydration sync from DB
167→    setMainTabs((prev) => {
168→      // Filter out orphaned session IDs (deleted from DB)
169→      const validTabs = prev.filter((t) => {
170→        const sid = t.data?.sessionId;
171→        return sid && sessionMap.has(sid);
172→      });
173→
174→      if (validTabs.length === 0) {
175→        // All persisted sessions are gone — fall back to active session
176→        const fallbackId = activeSessionId;
177→        const fallbackSession = fallbackId ? sessionMap.get(fallbackId) : undefined;
178→        const seq = fallbackSession ? computeSequences([fallbackSession]) : new Map();
179→        const tab = fallbackSession
180→          ? sessionToTab(fallbackSession, seq.get(fallbackId!) ?? 1)
181→          : {
182→              id: fallbackId ? `tab-${fallbackId}` : "tab-default",
183→              label: NEW_CHAT_LABEL,
184→              data: { sessionId: fallbackId ?? undefined, agentType: "claude", hasStarted: false },
185→            };
186→        setActiveMainTabId(tab.id);
187→        return [tab];
188→      }
189→
190→      // Compute sequences across all valid sessions in tab order
191→      const orderedSessions = validTabs
192→        .map((t) => sessionMap.get(t.data!.sessionId!)!)
193→        .filter(Boolean);
194→      const sequences = computeSequences(orderedSessions);
195→
196→      // Hydrate each placeholder with real session data
197→      const hydratedTabs = validTabs.map((t) => {
198→        const session = sessionMap.get(t.data!.sessionId!)!;
199→        return sessionToTab(session, sequences.get(session.id) ?? 1);
200→      });
201→
202→      // Fix active tab if it was orphaned
203→      setActiveMainTabId((prevActive) => {
204→        if (hydratedTabs.some((t) => t.id === prevActive)) return prevActive;
205→        return hydratedTabs[0]?.id ?? "tab-default";
206→      });
207→
208→      return hydratedTabs;
209→    });
210→  }, [workspaceSessions, sessionMap, activeSessionId]);
211→
212→  // --- Persist tab state to localStorage on every change ---
213→  // Debounced to avoid writing on every intermediate state update.
214→
215→  const persistTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
216→  useEffect(() => {
217→    clearTimeout(persistTimeoutRef.current);
218→    persistTimeoutRef.current = setTimeout(() => {
219→      const chatSessionIds = mainTabs
220→        .filter((t) => t.data?.sessionId)
221→        .map((t) => t.data!.sessionId!);
222→
223→      const activeTab = mainTabs.find((t) => t.id === activeMainTabId);
224→      const activeSessionIdForPersist = activeTab?.data?.sessionId ?? null;
225→
226→      workspaceLayoutActions.setChatTabState(
227→        workspaceId,
228→        chatSessionIds,
229→        activeSessionIdForPersist
230→      );
231→    }, 100);
232→
233→    return () => clearTimeout(persistTimeoutRef.current);
234→  }, [mainTabs, activeMainTabId, workspaceId]);
235→
236→  // --- Tab handlers ---
237→
238→  const handleTabChange = useCallback((tabId: string) => setActiveMainTabId(tabId), []);
239→
240→  const handleTabClose = useCallback(
241→    (tabId: string) => {
242→      setMainTabs((prev) => {
243→        if (prev.length <= 1) return prev;
244→
245→        const closingTab = prev.find((t) => t.id === tabId);
246→        const currentIndex = prev.findIndex((t) => t.id === tabId);
247→        const newTabs = prev.filter((t) => t.id !== tabId);
248→
249→        // Save closed tab for restore
250→        if (closingTab?.data?.sessionId) {
251→          setClosedTabs((prevClosed) => {
252→            const entry: ClosedTab = {
253→              label: closingTab.label,
254→              sessionId: closingTab.data!.sessionId!,
255→              agentType: closingTab.data?.agentType,
256→              closedAt: Date.now(),
257→            };
258→            return [entry, ...prevClosed].slice(0, MAX_CLOSED_TABS);
259→          });
260→        }
261→
262→        if (tabId === activeMainTabId && newTabs.length > 0) {
263→          const targetIndex = currentIndex > 0 ? currentIndex - 1 : 0;
264→          setActiveMainTabId(newTabs[targetIndex].id);
265→        }
266→        return newTabs;
267→      });
268→    },
269→    [activeMainTabId]
270→  );
271→
272→  const handleTabAdd = useCallback(
273→    async (initialModel?: string) => {
274→      try {
275→        const newSession = await createSessionMutation.mutateAsync(workspaceId);
276→        const agentType = initialModel ? getRuntimeAgentTypeForModel(initialModel) : "claude";
277→        const newId = `tab-${newSession.id}`;
278→        const newTab: Tab = {
279→          id: newId,
280→          label: NEW_CHAT_LABEL,
281→          data: {
282→            sessionId: newSession.id,
283→            agentType,
284→            hasStarted: false,
285→            initialModel,
286→          },
287→        };
288→        setMainTabs((prevTabs) => [...prevTabs, newTab]);
289→        setActiveMainTabId(newId);
290→      } catch (error) {
291→        console.error("[useChatTabs] Failed to create new session:", error);
292→        toast.error("Failed to create new chat session");
293→      }
294→    },
295→    [workspaceId, createSessionMutation]
296→  );
297→
298→  const handleTabRestore = useCallback((closedTab: ClosedTab) => {
299→    const newId = `tab-${closedTab.sessionId}`;
300→
301→    const restoredTab: Tab = {
302→      id: newId,
303→      label: closedTab.label,
304→      data: {
305→        sessionId: closedTab.sessionId,
306→        agentType: closedTab.agentType,
307→        hasStarted: closedTab.label !== NEW_CHAT_LABEL,
308→      },
309→    };
310→
311→    setMainTabs((prev) => {
312→      // Don't add duplicate if session is already open in a tab
313→      if (prev.some((t) => t.data?.sessionId === closedTab.sessionId)) {
314→        return prev;
315→      }
316→      return [...prev, restoredTab];
317→    });
318→    setActiveMainTabId(newId);
319→    setClosedTabs((prev) => prev.filter((ct) => ct.sessionId !== closedTab.sessionId));
320→  }, []);
321→
322→  const updateChatTabAgentType = useCallback((tabId: string, nextAgentType: RuntimeAgentType) => {
323→    setMainTabs((prevTabs) => {
324→      const tabIndex = prevTabs.findIndex((tab) => tab.id === tabId);
325→      if (tabIndex === -1) return prevTabs;
326→
327→      const tab = prevTabs[tabIndex];
328→      if (tab.data?.agentType === nextAgentType) return prevTabs;
329→
330→      const hasStarted = Boolean(tab.data?.hasStarted);
331→
332→      let nextLabel = hasStarted ? tab.label : NEW_CHAT_LABEL;
333→
334→      if (hasStarted) {
335→        const sequence = countStartedTabsOfType(prevTabs, nextAgentType, tabId) + 1;
336→        nextLabel = buildStartedChatLabel(nextAgentType, sequence);
337→      }
338→
339→      const updatedTabs = [...prevTabs];
340→      updatedTabs[tabIndex] = {
341→        ...tab,
342→        label: nextLabel,
343→        data: { ...tab.data, agentType: nextAgentType, hasStarted },
344→      };
345→      return updatedTabs;
346→    });
347→  }, []);
348→
349→  const markChatTabStarted = useCallback((tabId: string) => {
350→    setMainTabs((prevTabs) => {
351→      const tabIndex = prevTabs.findIndex((tab) => tab.id === tabId);
352→      if (tabIndex === -1) return prevTabs;
353→
354→      const tab = prevTabs[tabIndex];
355→      if (tab.data?.hasStarted) return prevTabs;
356→
357→      const agentType = (tab.data?.agentType as RuntimeAgentType | undefined) ?? "claude";
358→      const sequence = countStartedTabsOfType(prevTabs, agentType, tabId) + 1;
359→
360→      const updatedTabs = [...prevTabs];
361→      updatedTabs[tabIndex] = {
362→        ...tab,
363→        label: buildStartedChatLabel(agentType, sequence),
364→        data: { ...tab.data, agentType, hasStarted: true },
365→      };
366→      return updatedTabs;
367→    });
368→  }, []);
369→
370→  const handleTabReorder = useCallback((reorderedTabs: Tab[]) => {
371→    setMainTabs(reorderedTabs);
372→  }, []);
373→
374→  // --- Keyboard shortcuts ---
375→
376→  useEffect(() => {
377→    function handleKeyDown(e: KeyboardEvent) {
378→      const isModKey = e.metaKey || e.ctrlKey;
379→      const key = e.key.toLowerCase();
380→
381→      // Cmd+Shift+T — restore last closed tab (check before Cmd+T)
382→      if (isModKey && e.shiftKey && key === "t") {
383→        e.preventDefault();
384→        setClosedTabs((prev) => {
385→          if (prev.length === 0) return prev;
386→          const [latest, ...rest] = prev;
387→          queueMicrotask(() => handleTabRestore(latest));
388→          return rest;
389→        });
390→        return;
391→      }
392→
393→      // Cmd+T — new chat tab
394→      if (isModKey && key === "t") {
395→        const ae = document.activeElement as HTMLElement | null;
396→        const isTextField =
397→          !!ae &&
398→          (ae.tagName === "INPUT" ||
399→            ae.tagName === "TEXTAREA" ||
400→            ae.isContentEditable ||
401→            ae.getAttribute("role") === "textbox");
402→        if (isTextField) return;
403→
404→        e.preventDefault();
405→        handleTabAdd();
406→      }
407→    }
408→    window.addEventListener("keydown", handleKeyDown);
409→    return () => window.removeEventListener("keydown", handleKeyDown);
410→  }, [handleTabAdd, handleTabRestore]);
411→
412→  // --- Derived state ---
413→
414→  const activeTab = mainTabs.find((t) => t.id === activeMainTabId);
415→
416→  return {
417→    tabs: mainTabs,
418→    activeTabId: activeMainTabId,
419→    activeTab,
420→    closedTabs,
421→    handleTabChange,
422→    handleTabClose,
423→    handleTabAdd,
424→    handleTabReorder,
425→    handleTabRestore,
426→    updateChatTabAgentType,
427→    markChatTabStarted,
428→  };
429→}
