  3→ *
  4→ * Renders inside the content panel's header bar (36px), left-aligned.
  5→ * Active tab: filled pill (bg-bg-raised) with icon + text label.
  6→ * Inactive tabs: icon only with tooltip on hover.
  7→ *
  8→ * Tab definitions and visibility logic live in content-tabs.ts.
  9→ * This component is pure presentation — it renders icons/pills and fires onTabChange.
 10→ */
 11→
 12→import { useMemo } from "react";
 13→import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
