 37→  );
 38→
 39→  return (
 40→    <div
 41→      data-slot="content-tab-bar"
 42→      className="flex items-center gap-1"
 43→      role="tablist"
 44→      aria-label="Content panel"
 45→    >
 46→      {visibleItems.map((item) => {
 47→        const Icon = item.icon;
 48→        const isActive = activeTab === item.id;
 49→        const showDot = item.id === "simulator" && simulatorActive;
 50→
 51→        return isActive ? (
 52→          <button
 53→            key={item.id}
 54→            type="button"
 55→            role="tab"
 56→            aria-label={item.label}
 57→            aria-selected={true}
 58→            onClick={() => onTabChange(item.id)}
 59→            className={cn(
 60→              "bg-bg-raised text-text-secondary",
 61→              "relative flex h-7 items-center gap-1.5 rounded-lg px-3",
 62→              "text-sm font-medium",
 63→              "transition-colors duration-150"
 64→            )}
 65→          >
