 49→/**
 50→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 51→ * Must be rendered inside SidebarProvider to access sidebar open state.
 52→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 53→ */
 54→function SidebarResizeHandle({
 55→  onSizeChange,
 56→  onDraggingChange,
 57→}: {
 58→  onSizeChange: (size: number | null) => void;
 59→  onDraggingChange: (dragging: boolean) => void;
 60→}) {
 61→  const { open } = useSidebar();
 62→
 63→  const { handleProps, isDragging } = useResizeHandle({
 64→    onSizeChange,
 65→    enabled: open,
 66→    direction: "horizontal",
 67→    mode: "primary",
 68→    minPrimarySize: 200,
 69→    minSecondarySize: 400,
 70→  });
 71→
 72→  // Notify parent of drag state changes to disable sidebar transitions
 73→  useEffect(() => {
 74→    onDraggingChange(isDragging);
 75→  }, [isDragging, onDraggingChange]);
 76→
 77→  if (!open) return null;
 78→
 79→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 80→}
