 1→import { useEffect } from "react";
 2→import { useSortable } from "@dnd-kit/sortable";
 3→import { CSS } from "@dnd-kit/utilities";
 4→import { cn } from "@/shared/lib/utils";
 5→import type { RepositoryItemProps } from "../model/types";
 6→import { RepositoryItem } from "./RepositoryItem";
 7→
 8→interface DraggableRepositoryProps extends RepositoryItemProps {
 9→  dragDisabled?: boolean;
10→}
11→
12→/**
13→ * Draggable wrapper for RepositoryItem
14→ * Entire row is the drag target — click = expand/collapse, drag = reorder
15→ * PointerSensor distance constraint (in AppSidebar) differentiates the two
16→ * Auto-collapses on drag start (Linear pattern) for better drag experience
17→ */
18→export function DraggableRepository({
19→  repository,
20→  isCollapsed,
21→  onToggleCollapse,
22→  dragDisabled = false,
23→  ...props
24→}: DraggableRepositoryProps) {
25→  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
26→    id: repository.repo_id,
27→    disabled: dragDisabled,
28→    // Snappy spring-like transition for neighbors shifting (ease-out-quart 200ms)
29→    transition: {
30→      duration: 200,
31→      easing: "cubic-bezier(.165, .84, .44, 1)",
32→    },
33→  });
34→
35→  // Auto-collapse when drag starts (prevents huge drag preview with many workspaces)
36→  useEffect(() => {
37→    if (isDragging && !isCollapsed) {
38→      onToggleCollapse();
39→    }
40→  }, [isDragging, isCollapsed, onToggleCollapse]);
41→
42→  // Use Translate (not Transform) to avoid scaleX/scaleY stretching during drag
43→  const style = {
44→    transform: CSS.Translate.toString(transform),
45→    transition,
46→  };
47→
48→  return (
49→    <div
50→      ref={setNodeRef}
51→      style={style}
52→      {...attributes}
53→      {...listeners}
54→      className={cn(
55→        isDragging &&
56→          "z-50 cursor-grabbing rounded-lg opacity-70 shadow-lg shadow-black/20 [&_*]:cursor-grabbing"
57→      )}
58→    >
59→      <RepositoryItem
60→        repository={repository}
61→        isCollapsed={isCollapsed}
62→        onToggleCollapse={onToggleCollapse}
63→        {...props}
64→      />
65→    </div>
66→  );
67→}
