 90→    pulse: true,
 91→  },
 92→  idle: {
 93→    priority: StatusPriority.IDLE,
 94→    label: "Idle",
 95→    labelActive: "Idle",
 96→    badge: "bg-muted text-muted-foreground",
 97→    border: "border-muted",
 98→    text: "text-muted-foreground",
 99→    bg: "bg-muted/30",
100→    pulse: false,
101→  },
102→};
103→
104→// ── Workflow Status (Linear-style) ────────────────────────────────────────
105→// Separate from DisplayStatus which shows real-time agent activity.
106→// Rendered as a small icon to the left of the workspace title.
107→
108→export interface WorkflowStatusConfig {
109→  label: string;
110→  color: string;
111→}
112→
113→export const WORKFLOW_STATUS_CONFIG: Record<WorkspaceStatus, WorkflowStatusConfig> = {
114→  backlog: { label: "Backlog", color: "text-muted-foreground" },
115→  "in-progress": { label: "In Progress", color: "text-status-in-progress" },
116→  "in-review": { label: "In Review", color: "text-status-in-review" },
117→  done: { label: "Done", color: "text-status-done" },
118→  canceled: { label: "Canceled", color: "text-muted-foreground" },
119→};
120→
121→/**
122→ * Derive display status from workspace data
123→ *
124→ * Priority logic:
125→ * 1. Error — session in error state
126→ * 2. Unread — agent needs user response OR has unseen activity
127→ * 3. Working — agent actively processing
128→ * 4. Idle — dormant
129→ *
130→ * @param workspace Workspace data with session info
131→ * @param hasUnseenActivity Whether the session has activity the user hasn't viewed yet
132→ * @returns Derived display status for UI rendering
133→ */
134→export function getDisplayStatus(workspace: Workspace, hasUnseenActivity = false): DisplayStatus {
135→  const status = workspace.session_status;
136→
137→  if (status === "error") return "error";
138→  if (status === "needs_response" || status === "needs_plan_response") return "unread";
139→  if (status === "working") return "working";
140→  if (hasUnseenActivity) return "unread";
141→  return "idle";
142→}
143→
144→/**
145→ * Check if workspace needs user attention.
146→ * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
147→ */
148→export function getUnreadCount(workspace: Workspace): number {
149→  const status = workspace.session_status;
150→  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
151→}
152→
153→/**
154→ * Sort workspaces by status priority
155→ * Higher priority statuses appear first
156→ *
157→ * @param workspaces Array of workspaces to sort
158→ * @returns Sorted array (original array not mutated)
159→ */
160→export function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
161→  return [...workspaces].sort((a, b) => {
162→    const statusA = getDisplayStatus(a);
163→    const statusB = getDisplayStatus(b);
164→    const priorityA = STATUS_CONFIG[statusA].priority;
165→    const priorityB = STATUS_CONFIG[statusB].priority;
166→
167→    // Higher priority first
168→    if (priorityA !== priorityB) {
169→      return priorityB - priorityA;
170→    }
171→
172→    // Same priority: sort by latest activity (most recent first)
173→    const timeA = new Date(a.updated_at).getTime();
174→    const timeB = new Date(b.updated_at).getTime();
175→    return timeB - timeA;
176→  });
177→}
178→
179→/**
180→ * Group workspaces by display status
181→ * Used for rendering section headers in expanded sidebar
182→ *
183→ * @param workspaces Array of workspaces to group
184→ * @returns Object with status as keys, workspace arrays as values
185→ */
186→export function groupByStatus<T extends Workspace>(
187→  workspaces: T[]
188→): Partial<Record<DisplayStatus, T[]>> {
189→  const groups: Partial<Record<DisplayStatus, T[]>> = {};
190→
191→  workspaces.forEach((workspace) => {
192→    const status = getDisplayStatus(workspace);
193→    if (!groups[status]) {
194→      groups[status] = [];
195→    }
196→    groups[status]!.push(workspace);
197→  });
198→
199→  return groups;
200→}
201→
202→/**
203→ * Get aggregate status counts for a repository
204→ * Used for collapsed sidebar status indicators
205→ *
206→ * @param workspaces Workspaces in a repository
207→ * @returns Count of each status type
208→ */
209→export function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
210→  const counts: Record<DisplayStatus, number> = {
211→    error: 0,
212→    unread: 0,
213→    working: 0,
214→    idle: 0,
215→  };
216→
217→  workspaces.forEach((workspace) => {
218→    const status = getDisplayStatus(workspace);
219→    counts[status]++;
220→  });
221→
222→  return counts;
223→}
224→
225→/**
226→ * Get total unread count for a repository
227→ * Sums unread across all workspaces
228→ */
229→export function getRepoUnreadCount(workspaces: Workspace[]): number {
230→  return workspaces.reduce((sum, workspace) => {
231→    return sum + getUnreadCount(workspace);
232→  }, 0);
233→}
234→
235→/**
236→ * Get highest priority status for a repository
237→ * Used for collapsed sidebar badge color
238→ *
239→ * @param workspaces Workspaces in a repository
240→ * @returns The highest priority status present
241→ */
242→export function getRepoPriorityStatus(workspaces: Workspace[]): DisplayStatus {
243→  let highestPriority = StatusPriority.IDLE;
244→  let highestStatus: DisplayStatus = "idle";
245→
246→  workspaces.forEach((workspace) => {
247→    const status = getDisplayStatus(workspace);
248→    const priority = STATUS_CONFIG[status].priority;
249→
250→    if (priority > highestPriority) {
251→      highestPriority = priority;
252→      highestStatus = status;
253→    }
254→  });
255→
256→  return highestStatus;
257→}
