 17→/**
 18→ * WorkspaceItem — Sidebar workspace row
 19→ *
 20→ * Layout:  [Left (flex-1)]  [Right]
 21→ *   Left:
 22→ *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 23→ *     Row 2: [pad-left 26px] [secondary · status]
 24→ *   Right:
 25→ *     [+additions -deletions]
 26→ *
 27→ * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 28→ * Secondary line: shows slug when title is primary, otherwise just status info.
 29→ *
 30→ * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 31→ * Idle → no icon (26px indent).
 32→ *
 33→ * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 34→ */
 35→export const WorkspaceItem = React.memo(function WorkspaceItem({
 36→  workspace,
 37→  isActive,
 38→  diffStats,
 39→  onClick,
 40→  onArchive,
 41→  onStatusChange,
 42→}: WorkspaceItemProps) {
 43→  const isInitializing = workspace.state === "initializing";
 44→
 45→  // Hooks must be called unconditionally (React rules of hooks)
 46→  const { duration } = useWorkingDuration({
 47→    status: workspace.session_status,
 48→    latestMessageSentAt: workspace.latest_message_sent_at,
 49→  });
 50→
 51→  // Initializing state: non-interactive row with loading animation
 52→  if (isInitializing) {
 53→    const initSecondary = getWorkspaceSecondaryText(workspace);
 54→    return (
 55→      <div className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 56→        <SidebarRow
 57→          variant="workspace"
 58→          isActive={false}
 59→          aria-label="Workspace setting up"
 60→          className="pointer-events-none"
 61→        >
 62→          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
 63→            {/* Row 1: thinking icon + display name */}
 64→            <div className="flex min-w-0 items-center gap-1.5">
 65→              <SidebarRowIconSlot>
 66→                <CircularPixelGrid variant="working" size={14} resolution={8} />
 67→              </SidebarRowIconSlot>
 68→              <span className="text-text-disabled truncate text-base font-normal">
 69→                {getWorkspaceDisplayName(workspace)}
 70→              </span>
 71→            </div>
 72→            {/* Row 2: secondary context · init stage */}
 73→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 74→              {initSecondary && (
 75→                <>
 76→                  <span className="text-text-disabled truncate text-xs">{initSecondary}</span>
 77→                  <span className="text-text-disabled text-xs">·</span>
 78→                </>
 79→              )}
 80→              <span className="text-text-muted shrink-0 text-xs">
 81→                {match(workspace.init_stage)
 82→                  .with("worktree", () => "Creating worktree...")
 83→                  .with("dependencies", () => "Installing dependencies...")
 84→                  .with("hooks", () => "Setting up environment...")
 85→                  .with("session", () => "Finalizing...")
 86→                  .otherwise(() => "Setting up...")}
 87→              </span>
 88→            </div>
 89→          </div>
 90→        </SidebarRow>
 91→      </div>
 92→    );
 93→  }
 94→
 95→  const formatTime = (timestamp: string) => {
 96→    const date = new Date(timestamp);
 97→    const now = new Date();
 98→    const diffMs = now.getTime() - date.getTime();
 99→    const diffMins = Math.floor(diffMs / 60000);
100→    const diffHours = Math.floor(diffMins / 60);
101→    const diffDays = Math.floor(diffHours / 24);
102→    const diffMonths = Math.floor(diffDays / 30);
103→
104→    if (diffMins < 1) return "now";
105→    if (diffMins < 60) return `${diffMins}m ago`;
106→    if (diffHours < 24) return `${diffHours}h ago`;
107→    if (diffDays < 30) return `${diffDays}d ago`;
108→    return `${diffMonths}mo ago`;
109→  };
110→
111→  const sessionId = workspace.current_session_id;
112→  const hasUnseenActivity = useUnreadStore(
113→    (s) => !!sessionId && !!s.unreadSessionIds[sessionId]
114→  );
115→  const displayStatus = getDisplayStatus(workspace, hasUnseenActivity);
116→  const statusConfig = STATUS_CONFIG[displayStatus];
117→  // Session activity icons take priority over workflow status
118→  const hasSessionIcon =
119→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
120→
121→  const isSetupRunning = workspace.setup_status === "running";
122→  const isSetupFailed = workspace.setup_status === "failed";
123→
124→  const statusTextClass = isSetupFailed
125→    ? "text-accent-red-muted"
126→    : isSetupRunning
127→      ? "text-text-muted"
128→      : match(displayStatus)
129→          .with("working", () => "text-text-tertiary")
130→          .with("unread", () => "text-text-secondary")
131→          .with("error", () => "text-accent-red-muted")
132→          .otherwise(() => "text-text-disabled");
133→
134→  const getStatusText = (): string => {
135→    if (isSetupRunning) return "Installing...";
136→    if (isSetupFailed) return "Setup failed";
137→    if (workspace.state === "archived") return "Archived";
138→    if (!workspace.session_status) return formatTime(workspace.updated_at);
139→
140→    return match(displayStatus)
141→      .with("idle", () => formatTime(workspace.updated_at))
142→      .with("unread", () => {
143→        const sessionStatus = workspace.session_status;
144→        if (sessionStatus === "needs_response" || sessionStatus === "needs_plan_response") {
145→          return "Needs response";
146→        }
147→        return "Done";
148→      })
149→      .with("working", () =>
150→        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
151→      )
152→      .with("error", () => STATUS_CONFIG.error.label)
153→      .otherwise(() => statusConfig.label);
154→  };
155→
156→  const statusText = getStatusText();
157→  const displayName = getWorkspaceDisplayName(workspace);
158→  const secondaryText = getWorkspaceSecondaryText(workspace);
159→  const showStatusDot = Boolean(secondaryText && statusText);
160→
161→  const additions = diffStats?.additions ?? 0;
162→  const deletions = diffStats?.deletions ?? 0;
163→  const hasChanges = additions > 0 || deletions > 0;
164→
165→  const handleArchive = (e: React.MouseEvent) => {
166→    e.stopPropagation();
167→    if (onArchive) {
168→      onArchive(workspace.id);
169→    }
170→  };
171→
172→  const isArchived = workspace.state === "archived";
173→  const canArchive = !isArchived && !!onArchive;
174→  const isActiveState =
175→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
176→
177→  return (
178→    <div>
179→      <SidebarRow
180→        variant="workspace"
181→        isActive={isActive}
182→        role="button"
183→        tabIndex={0}
184→        data-workspace-id={workspace.id}
185→        className="cursor-pointer"
186→        aria-current={isActive ? "page" : undefined}
187→        aria-label={`Workspace ${displayName}`}
188→        onClick={() => onClick(workspace)}
189→        onKeyDown={(e) => {
190→          if (e.key === " ") e.preventDefault();
191→        }}
192→        onKeyUp={(e) => {
193→          if (e.key === "Enter" || e.key === " ") onClick(workspace);
194→        }}
195→      >
196→        {/* Left: rows */}
197→        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
198→          {/* Row 1: icon + display name (title > slug > branch) */}
199→          <div className="flex min-w-0 items-center gap-1.5">
200→            <WorkspaceStatusMenu
201→              currentStatus={workspace.status}
202→              onStatusChange={(status) => onStatusChange?.(workspace.id, status)}
203→            >
204→              <button
205→                type="button"
206→                onClick={(e) => e.stopPropagation()}
207→                className="flex h-5 w-5 shrink-0 items-center justify-center rounded transition-opacity hover:opacity-80"
208→                aria-label={`Status: ${workspace.status}`}
209→              >
210→                {hasSessionIcon ? (
211→                  match(displayStatus)
212→                    .with("working", () => (
213→                      <CircularPixelGrid variant="working" size={14} resolution={8} />
214→                    ))
215→                    .with("error", () => <span className="bg-accent-red h-2 w-2 rounded-full" />)
216→                    .otherwise(() => <span className="bg-accent-gold h-2 w-2 rounded-full" />)
217→                ) : (
218→                  <WorkflowStatusIcon status={workspace.status} size={14} />
219→                )}
220→              </button>
221→            </WorkspaceStatusMenu>
222→            <span
223→              className={cn(
224→                "truncate text-base",
225→                isActive
226→                  ? "text-text-primary font-medium"
227→                  : isActiveState
228→                    ? "text-text-primary font-normal"
229→                    : "text-text-tertiary font-normal"
230→              )}
231→            >
232→              {displayName}
233→            </span>
234→          </div>
235→
236→          {/* Row 2: secondary context · status */}
237→          <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
238→            {secondaryText && (
239→              <span
240→                className={cn(
241→                  "truncate text-xs",
242→                  isActiveState ? "text-text-tertiary" : "text-text-disabled"
243→                )}
244→              >
245→                {secondaryText}
246→              </span>
247→            )}
248→            {showStatusDot && (
249→              <span
250→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
251→              >
252→                ·
253→              </span>
254→            )}
255→            {statusText && (
256→              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
257→                {isSetupRunning && (
258→                  <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />
259→                )}
260→                {statusText}
261→              </span>
262→            )}
263→          </div>
264→        </div>
265→
266→        {/* Right: diff stats */}
267→        {hasChanges ? (
268→          <div
269→            className={cn(
270→              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
271→              canArchive && "group-hover/sidebar-row:opacity-0"
272→            )}
273→          >
274→            {additions > 0 && (
275→              <NumberFlow
276→                value={additions}
277→                prefix="+"
278→                className={isActive ? "text-accent-green" : "text-text-muted"}
279→              />
280→            )}
281→            {deletions > 0 && (
282→              <NumberFlow
283→                value={deletions}
284→                prefix="-"
285→                className={isActive ? "text-accent-red" : "text-text-muted"}
286→              />
287→            )}
288→          </div>
289→        ) : null}
290→
291→        {/* Archive button — hover reveal */}
292→        {canArchive ? (
293→          <button
294→            type="button"
295→            onClick={handleArchive}
296→            aria-label={`Archive workspace ${displayName}`}
297→            title="Archive workspace"
298→            className={cn(
299→              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
300→              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
301→              "group-hover/sidebar-row:opacity-100"
302→            )}
303→          >
304→            <Archive className="h-3.5 w-3.5" />
305→          </button>
306→        ) : null}
307→      </SidebarRow>
308→    </div>
309→  );
310→});
