  1→/**
  2→ * Chat Area — renders the active chat tab and wires up the tab bar.
  3→ *
  4→ * Tab lifecycle (create, close, restore, labels) is managed by useChatTabs.
  5→ * This component focuses on layout and connecting tabs to SessionPanel.
  6→ */
  7→
  8→import { useMemo, useEffect } from "react";
  9→import type { Dispatch, SetStateAction } from "react";
 10→import { SessionPanel } from "@/features/session";
 11→import type { SessionPanelRef } from "@/features/session";
 12→import { useWorkingSessionIds } from "@/features/session/api/session.queries";
 13→import { useUnreadStore, unreadActions } from "@/features/session/store/unreadStore";
 14→import { WorkspaceEmptyState } from "@/features/session/ui/WorkspaceEmptyState";
 15→import { MainContentTabBar } from "@/features/workspace";
 16→import type { Workspace } from "@/shared/types";
 17→import { useChatTabs } from "./useChatTabs";
 18→
 19→interface ChatAreaProps {
 20→  workspace: Workspace;
 21→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 22→  onCreatePRHandlerChange: (handler: (() => void) | null) => void;
 23→  onSendAgentMessageHandlerChange: Dispatch<
 24→    SetStateAction<((text: string) => Promise<void>) | null>
 25→  >;
 26→  onCollapseChatPanel?: () => void;
 27→}
 28→
 29→export function ChatArea({
 30→  workspace,
 31→  workspaceChatPanelRef,
 32→  onCreatePRHandlerChange,
 33→  onSendAgentMessageHandlerChange,
 34→  onCollapseChatPanel,
 35→}: ChatAreaProps) {
 36→  const {
 37→    tabs,
 38→    activeTabId,
 39→    activeTab,
 40→    closedTabs,
 41→    handleTabChange,
 42→    handleTabClose,
 43→    handleTabAdd,
 44→    handleTabReorder,
 45→    handleTabRestore,
 46→    updateChatTabAgentType,
 47→    markChatTabStarted,
 48→  } = useChatTabs({
 49→    workspaceId: workspace.id,
 50→    activeSessionId: workspace.current_session_id,
 51→  });
 52→
 53→  // Resolve sessionId: tab's own session, falling back to workspace's active session
 54→  const tabSessionId = activeTab?.data?.sessionId || workspace.current_session_id;
 55→
 56→  // Per-tab working status: subscribes to each chat tab's session detail cache
 57→  // so each tab's spinner reflects its own session's status (not the workspace's
 58→  // single session_status which breaks with multiple tabs).
 59→  const chatSessionIds = useMemo(
 60→    () => tabs.filter((t) => t.data?.sessionId).map((t) => t.data!.sessionId!),
 61→    [tabs]
 62→  );
 63→  const workingSessionIds = useWorkingSessionIds(chatSessionIds);
 64→
 65→  // Unread tracking: build a set of session IDs with unseen activity for tab dots
 66→  const unreadMap = useUnreadStore((s) => s.unreadSessionIds);
 67→  const unreadSessionIds = useMemo(() => {
 68→    const ids = new Set<string>();
 69→    for (const sid of chatSessionIds) {
 70→      if (unreadMap[sid]) ids.add(sid);
 71→    }
 72→    return ids;
 73→  }, [chatSessionIds, unreadMap]);
 74→
 75→  // Mark the active tab's session as read when it becomes active
 76→  const activeSessionId = activeTab?.data?.sessionId;
 77→  useEffect(() => {
 78→    if (activeSessionId) {
 79→      unreadActions.markRead(activeSessionId);
 80→    }
 81→  }, [activeSessionId]);
 82→
 83→  return (
 84→    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
 85→      <MainContentTabBar
 86→        tabs={tabs}
 87→        activeTabId={activeTabId}
 88→        workingSessionIds={workingSessionIds}
 89→        unreadSessionIds={unreadSessionIds}
 90→        onTabChange={handleTabChange}
 91→        onTabClose={handleTabClose}
 92→        onTabAdd={handleTabAdd}
 93→        onTabReorder={handleTabReorder}
 94→        closedTabs={closedTabs}
 95→        onTabRestore={handleTabRestore}
 96→        onCollapseChatPanel={onCollapseChatPanel}
 97→      />
 98→
 99→      <div className="flex min-h-0 flex-1 flex-col overflow-hidden">
100→        {tabSessionId && (
101→          <SessionPanel
102→            key={tabSessionId}
103→            ref={workspaceChatPanelRef}
104→            sessionId={tabSessionId}
105→            workspaceId={workspace.id}
106→            workspacePath={workspace.workspace_path}
107→            workspaceRepoName={workspace.repo_name}
108→            workspaceParentBranch={workspace.git_target_branch}
109→            workspaceDefaultBranch={workspace.git_default_branch}
110→            isFirstSession={workspace.latest_message_sent_at === null}
111→            embedded={true}
112→            initialModel={activeTab?.data?.initialModel}
113→            onAgentTypeChange={(agentType) =>
114→              activeTab && updateChatTabAgentType(activeTab.id, agentType)
115→            }
116→            onSessionStarted={() => activeTab && markChatTabStarted(activeTab.id)}
117→            onOpenNewTab={handleTabAdd}
118→            onCreatePR={(handler) => onCreatePRHandlerChange(() => handler)}
119→            onSendAgentMessage={(handler) => onSendAgentMessageHandlerChange(() => handler)}
120→          />
121→        )}
122→
123→        {/* Workspace still initializing — show the same empty state with init progress */}
124→        {!tabSessionId && (
125→          <WorkspaceEmptyState
126→            repoName={workspace.repo_name}
127→            parentBranch={workspace.git_target_branch}
128→            isFirstSession={true}
129→            initializing={workspace.state === "initializing"}
130→            initStep={workspace.init_stage}
131→          />
132→        )}
133→      </div>
134→    </div>
135→  );
136→}
