 83→export function MainLayout() {
 84→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 85→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 86→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 87→
 88→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
 89→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
 90→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
 91→  const settingsOpen = useUIStore((s) => s.settingsOpen);
 92→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
 93→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
 94→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
 95→
 96→  // TanStack Query
 97→  const workspacesQuery = useWorkspacesByRepo();
 98→
 99→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
100→  const loading = workspacesQuery.isLoading;
101→
102→  // Derive the full workspace object from React Query data.
103→  // The store only holds an ID; this useMemo resolves it to a Workspace
104→  // on every React Query refresh, eliminating the old sync effect entirely.
105→  const selectedWorkspace = useMemo(() => {
106→    if (!selectedWorkspaceId || !repoGroups.length) return null;
107→    for (const group of repoGroups) {
108→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
109→      if (found) return found;
110→    }
111→    return null;
112→  }, [selectedWorkspaceId, repoGroups]);
113→
114→  const selectedWorkspaceIdRef = useRef(selectedWorkspaceId);
115→  useEffect(() => {
116→    selectedWorkspaceIdRef.current = selectedWorkspaceId;
117→  });
118→
119→  // Bulk-fetch diff stats for all workspaces (replaces per-item useDiffStats in sidebar)
120→  const bulkDiffStatsQuery = useBulkDiffStats(repoGroups);
121→
122→  // Sidebar resize: null = default 344px, number = user-set width
123→  const [sidebarWidth, setSidebarWidth] = useState<number | null>(null);
124→  // Tracks drag state to disable sidebar CSS transitions during resize
125→  const [sidebarDragging, setSidebarDragging] = useState(false);
126→
127→  // GitHub picker modal state
128→  const [githubPickerRepoId, setGithubPickerRepoId] = useState<string | null>(null);
129→
130→  // Ref for inserting text from browser element selector
131→  const workspaceChatPanelRef = useRef<SessionPanelRef | null>(null);
132→
133→  // Queries for repos, settings
134→  const reposQuery = useRepos();
135→  const settingsQuery = useSettingsQuery();
136→
137→  const repos = reposQuery.data || [];
138→  const username = settingsQuery.data?.user_name || "My Account";
139→
140→  // GitHub CLI status — gates PR polling (like Codex)
141→  const ghStatusQuery = useGhStatus();
142→
143→  // PR status query — gated on gh CLI, polls while agent is working
144→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
145→    ghInstalled: ghStatusQuery.data?.isInstalled,
146→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
147→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
148→  });
149→
150→  // --- Extracted hooks ---
151→
152→  const repoActions = useRepoActions({
153→    selectWorkspace,
154→    openNewWorkspaceModal,
155→    closeNewWorkspaceModal,
156→  });
157→
158→  // Derive repo name for GitHub picker modal from repoGroups
159→  const githubPickerRepoName = useMemo(() => {
160→    if (!githubPickerRepoId) return "";
161→    const group = repoGroups.find((g) => g.repo_id === githubPickerRepoId);
162→    return group?.repo_name ?? "";
163→  }, [githubPickerRepoId, repoGroups]);
164→
165→  // Hide native WebContentsViews when any dialog is open — they render above
166→  // the DOM so dialogs would appear behind them. BrowserTab's own visible
167→  // effect handles re-showing when the dialog closes.
168→  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
169→  const anyDialogOpen =
170→    showNewWorkspaceModal ||
171→    showSystemPromptModal ||
172→    commandPaletteOpen ||
173→    !!githubPickerRepoId ||
174→    repoActions.showCloneModal;
175→  useEffect(() => {
176→    if (anyDialogOpen) {
177→      native.browserViews.hideAll().catch(() => {});
178→    }
179→  }, [anyDialogOpen]);
180→
181→  // --- System prompt (inline — small scope, one modal) ---
182→
183→  const systemPromptQuery = useSystemPrompt(selectedWorkspace?.id || null);
184→  const updateSystemPromptMutation = useUpdateSystemPrompt();
185→  // Track user edits separately; reset to null when modal closes so the
186→  // derived value from the query takes over again (no useEffect + setState).
187→  const [systemPromptEdit, setSystemPromptEdit] = useState<string | null>(null);
188→  const systemPromptDraft = systemPromptEdit ?? (systemPromptQuery.data || "");
189→  const setSystemPromptDraft = useCallback((value: string) => setSystemPromptEdit(value), []);
190→
191→  async function saveSystemPrompt() {
192→    if (!selectedWorkspace) return;
193→    try {
194→      await updateSystemPromptMutation.mutateAsync({
195→        workspaceId: selectedWorkspace.id,
196→        systemPrompt: systemPromptDraft,
197→      });
198→      closeSystemPromptModal();
199→      setSystemPromptEdit(null);
200→    } catch (error) {
201→      console.error("Failed to save system prompt:", error);
202→      toast.error(getErrorMessage(error));
203→    }
204→  }
205→
206→  // --- Archive with undo (ref-stable for memoized sidebar items) ---
207→
208→  const archiveWorkspaceMutation = useArchiveWorkspace();
209→  const unarchiveMutation = useUnarchiveWorkspace();
210→
211→  // Ref-stable archive handler: archiveWorkspaceMutation and selectedWorkspace
212→  // change frequently (every render / every workspace click), so we capture
213→  // them in refs to keep the callback identity stable. This matters because
214→  // onArchive flows through the entire sidebar tree to every memoized WorkspaceItem.
215→  const archiveMutationRef = useRef(archiveWorkspaceMutation);
216→  const unarchiveMutationRef = useRef(unarchiveMutation);
217→  const selectedWorkspaceRef = useRef(selectedWorkspace);
218→  useEffect(() => {
219→    archiveMutationRef.current = archiveWorkspaceMutation;
220→    unarchiveMutationRef.current = unarchiveMutation;
221→    selectedWorkspaceRef.current = selectedWorkspace;
222→  });
223→
224→  const archiveWorkspace = useCallback(
225→    async (workspaceId: string) => {
226→      try {
227→        await archiveMutationRef.current.mutateAsync(workspaceId);
228→        if (selectedWorkspaceRef.current?.id === workspaceId) {
229→          selectWorkspace(null);
230→        }
231→        toast("Workspace archived", {
232→          duration: 5000,
233→          action: {
234→            label: "Undo",
235→            onClick: () => {
236→              unarchiveMutationRef.current.mutateAsync(workspaceId).catch((error) => {
237→                toast.error(getErrorMessage(error));
238→              });
239→            },
240→          },
241→        });
242→      } catch (error) {
243→        console.error("Error archiving workspace:", error);
244→        toast.error(getErrorMessage(error));
245→      }
246→    },
247→    [selectWorkspace]
248→  );
249→
250→  // --- Workflow status change (ref-stable like archive) ---
251→
252→  const statusMutation = useUpdateWorkspaceStatus();
253→  const statusMutationRef = useRef(statusMutation);
254→  useEffect(() => {
255→    statusMutationRef.current = statusMutation;
256→  });
257→
258→  const handleStatusChange = useCallback(
259→    (workspaceId: string, status: import("@shared/enums").WorkspaceStatus) => {
260→      statusMutationRef.current.mutate(
261→        { workspaceId, status },
262→        { onError: (error) => toast.error(getErrorMessage(error)) }
263→      );
264→    },
265→    []
266→  );
267→
268→  // --- Global hooks ---
269→
270→  // Connection state machine — subscribes to WS changes + send-attempt-failed events
271→  useConnectionStateInit();
272→
273→  // Zoom (Cmd+=/Cmd+-/Cmd+0)
274→  useZoom();
275→
276→  // Track fullscreen state — toggles `.fullscreen` class on <html> for CSS
277→  useIsFullscreen();
278→
279→  // Adds .electron class to <html> and injects CSS-only drag region rules.
280→  // Headers with .drag-region class become draggable; buttons auto-excluded.
281→  useWindowDragZone();
282→
283→  // Disable CSS transitions during native window resize to prevent content "sticking"
284→  useWindowResizing();
285→
286→  // Keyboard shortcuts
287→  useKeyboardShortcuts({
288→    onRefresh: async () => {
289→      workspacesQuery.refetch();
290→      if (selectedWorkspace) {
291→        prStatusQuery.refetch();
292→      }
293→    },
294→    onEscape: () => {
