  const unreadKey = useUnreadStore((s) => {
    let key = "";
    for (const sid of repoSessionIds) {
      if (s.unreadSessionIds[sid]) key += sid + ",";
    }
    return key;
  });
  const unreadSessionIds = useMemo(() => {
    if (!unreadKey) return undefined;
    const ids = new Set<string>();
    for (const sid of unreadKey.split(",")) {
      if (sid) ids.add(sid);
    }
    return ids;
  }, [unreadKey]);
