  1→/**
  2→ * Global Session Notifications
  3→ *
  4→ * Sends OS-level notifications when the app is in the background.
  5→ *
  6→ * Notification triggers:
  7→ * - Agent finished working (working → idle)                → Glass sound
  8→ * - Agent error (→ error with error_category)              → Basso sound
  9→ * - Agent needs input (→ needs_response)                   → Ping sound
 10→ * - Plan ready for review (→ needs_plan_response)          → Ping sound
 11→ * - Setup failed/completed                                 → Basso/Glass sound
 12→ *
 13→ * All transitions are detected by observing the workspace React Query cache,
 14→ * which is kept fresh by the WS subscription. No IPC event listeners needed.
 15→ *
 16→ * When the app is in the foreground, notifications are suppressed —
 17→ * Sonner toasts handle in-app feedback.
 18→ */
 19→
 20→import { useEffect, useRef } from "react";
 21→import { useQueryClient } from "@tanstack/react-query";
 22→import { match } from "ts-pattern";
 23→import { capabilities } from "@/platform/capabilities";
 24→import { sendNotification } from "@/platform/notifications";
 25→import { isWindowFocused } from "@/shared/hooks/useWindowFocus";
 26→import { track } from "@/platform/analytics";
 27→import { unreadActions } from "@/features/session/store/unreadStore";
 28→import { useWorkspaceStore } from "@/features/workspace/store";
 29→import { workspaceLayoutActions } from "@/features/workspace/store/workspaceLayoutStore";
 30→import type { SessionStatus } from "@shared/types/session";
 31→import type { RepoGroup, SetupStatus } from "@shared/types/workspace";
 32→
 33→/**
 34→ * Batches multiple notifications within a short window into a single one.
 35→ * Prevents notification spam when multiple agents finish simultaneously.
 36→ */
 37→const BATCH_WINDOW_MS = 1500;
 38→
 39→/**
 40→ * Check if the user is currently viewing a specific session.
 41→ * True when the workspace is selected AND the active chat tab matches the session.
 42→ */
 43→function isUserViewingSession(workspaceId: string, sessionId: string): boolean {
 44→  const selectedWorkspaceId = useWorkspaceStore.getState().selectedWorkspaceId;
 45→  if (selectedWorkspaceId !== workspaceId) return false;
 46→
 47→  const layout = workspaceLayoutActions.getLayout(workspaceId);
 48→  // If no persisted active tab, the workspace's current_session_id is shown
 49→  return layout.activeChatTabSessionId === sessionId || !layout.activeChatTabSessionId;
 50→}
 51→
 52→export function useGlobalSessionNotifications() {
 53→  const prevStatusMap = useRef(new Map<string, SessionStatus>());
 54→  const prevSetupStatusMap = useRef(new Map<string, SetupStatus>());
 55→  const finishedBatch = useRef<string[]>([]);
 56→  const batchTimerRef = useRef<ReturnType<typeof setTimeout>>();
 57→
 58→  const queryClient = useQueryClient();
 59→
 60→  useEffect(() => {
 61→    const canNotify = capabilities.nativeNotifications;
 62→
 63→    function flushFinishedBatch() {
 64→      const batch = finishedBatch.current;
 65→      finishedBatch.current = [];
 66→      batchTimerRef.current = undefined;
 67→
 68→      if (batch.length === 0 || isWindowFocused()) return;
 69→
 70→      if (batch.length === 1) {
 71→        sendNotification({
 72→          title: "Agent finished",
 73→          body: `Session ${batch[0].substring(0, 8)} completed`,
 74→          sound: "Glass",
 75→        });
 76→      } else {
 77→        sendNotification({
 78→          title: `${batch.length} agents finished`,
 79→          body: "Multiple sessions completed",
 80→          sound: "Glass",
 81→        });
 82→      }
 83→    }
 84→
 85→    function queueFinished(sessionId: string) {
 86→      finishedBatch.current.push(sessionId);
 87→      if (!batchTimerRef.current) {
 88→        batchTimerRef.current = setTimeout(flushFinishedBatch, BATCH_WINDOW_MS);
 89→      }
 90→    }
 91→
 92→    // Detect all session + setup transitions from the workspace cache.
 93→    // The WS subscription pushes updated workspace rows including
 94→    // session_status, session_error_category, and session_error_message.
 95→    const unsubscribe = queryClient.getQueryCache().subscribe((event) => {
 96→      if (event.type !== "updated" || !event.query.queryKey[0]) return;
 97→
 98→      const key = event.query.queryKey;
 99→      if (key[0] !== "workspaces" || key[1] !== "by-repo") return;
100→
101→      const groups = event.query.state.data as RepoGroup[] | undefined;
102→      if (!groups) return;
103→
104→      for (const group of groups) {
105→        for (const ws of group.workspaces) {
106→          // --- Session status transitions ---
107→          if (ws.current_session_id && ws.session_status) {
108→            const sessionId = ws.current_session_id;
109→            const status = ws.session_status as SessionStatus;
110→            const prevStatus = prevStatusMap.current.get(sessionId);
111→            prevStatusMap.current.set(sessionId, status);
112→
113→            if (prevStatus && prevStatus !== status) {
114→              // Mark session as unread when transitioning out of "working"
115→              // to any terminal state — but only if user is not currently
116→              // viewing that exact session.
117→              if (
118→                prevStatus === "working" &&
119→                (status === "idle" || status === "error" || status === "needs_response" || status === "needs_plan_response")
120→              ) {
121→                const isViewingSession = isUserViewingSession(ws.id, sessionId);
122→                if (!isViewingSession) {
123→                  unreadActions.markUnread(sessionId);
124→                }
125→              }
126→
127→              // working → idle = agent finished
128→              if (prevStatus === "working" && status === "idle") {
129→                track("ai_turn_completed", { session_id: sessionId });
130→                if (canNotify && !isWindowFocused()) queueFinished(sessionId);
131→              }
132→
133→              // → needs_response = agent needs user input
134→              if (status === "needs_response" && canNotify && !isWindowFocused()) {
135→                sendNotification({
136→                  title: "Agent needs input",
137→                  body: `Session ${sessionId.substring(0, 8)} is waiting for your response`,
138→                  sound: "Ping",
139→                });
140→              }
141→
142→              // → needs_plan_response = plan ready for review
143→              if (status === "needs_plan_response" && canNotify && !isWindowFocused()) {
144→                sendNotification({
145→                  title: "Plan ready for review",
146→                  body: `Session ${sessionId.substring(0, 8)} has a plan waiting for approval`,
147→                  sound: "Ping",
148→                });
149→              }
150→
151→              // → error = agent errored (with category-aware title)
152→              if (status === "error") {
153→                const category = ws.session_error_category ?? undefined;
154→                track("session_error_displayed", {
155→                  session_id: sessionId,
156→                  error_category: category,
157→                });
158→
159→                if (canNotify && !isWindowFocused()) {
160→                  const title = match(category)
161→                    .with("auth", () => "Authentication Error")
162→                    .with("rate_limit", () => "Rate Limited")
163→                    .with("context_limit", () => "Context Limit Reached")
164→                    .with("network", () => "Network Error")
165→                    .with("db_write", () => "Database Error")
166→                    .with("process_exit", () => "Agent Process Crashed")
167→                    .otherwise(() => "Agent Error");
168→                  sendNotification({
169→                    title,
170→                    body:
171→                      ws.session_error_message ||
172→                      `Session ${sessionId.substring(0, 8)} encountered an error`,
173→                    sound: "Basso",
174→                  });
175→                }
176→              }
177→            }
178→          }
179→
180→          // --- Setup status transitions ---
181→          const prevSetup = prevSetupStatusMap.current.get(ws.id);
182→          prevSetupStatusMap.current.set(ws.id, ws.setup_status);
183→
184→          if (!prevSetup) continue;
185→          if (prevSetup === ws.setup_status) continue;
186→
187→          if (
188→            prevSetup === "running" &&
189→            (ws.setup_status === "failed" || ws.setup_status === "completed")
190→          ) {
191→            track("workspace_setup_completed", {
192→              workspace_id: ws.id,
193→              setup_status: ws.setup_status,
194→            });
195→          }
196→
197→          if (prevSetup === "running" && ws.setup_status === "failed" && canNotify && !isWindowFocused()) {
198→            sendNotification({
199→              title: "Setup failed",
200→              body: `Workspace ${ws.title || ws.slug} setup failed${ws.error_message ? `: ${ws.error_message}` : ""}`,
201→              sound: "Basso",
202→            });
203→          }
204→
205→          if (prevSetup === "running" && ws.setup_status === "completed") {
206→            queryClient.invalidateQueries({ queryKey: ["workspaces", "manifest", ws.id] });
207→            if (canNotify && !isWindowFocused()) {
208→              sendNotification({
209→                title: "Setup complete",
210→                body: `Workspace ${ws.title || ws.slug} is ready`,
211→                sound: "Glass",
212→              });
213→            }
214→          }
215→        }
216→      }
217→    });
218→
219→    return () => {
220→      unsubscribe();
221→      if (batchTimerRef.current) clearTimeout(batchTimerRef.current);
222→    };
223→  }, [queryClient]);
224→}
