  6→import { cn } from "@/shared/lib/utils";
  7→import { useWorkingDuration, formatDuration } from "@/shared/hooks";
  8→import { CircularPixelGrid } from "@/features/session/ui/CircularPixelGrid";
  9→import { useUnreadStore } from "@/features/session/store/unreadStore";
 10→import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
 11→import { getWorkspaceDisplayName, getWorkspaceSecondaryText } from "../lib/utils";
 12→import type { WorkspaceItemProps } from "../model/types";
 13→import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
 14→import { WorkflowStatusIcon } from "./WorkflowStatusIcon";
 15→import { WorkspaceStatusMenu } from "./WorkspaceStatusMenu";
 16→
 17→/**
 18→ * WorkspaceItem — Sidebar workspace row
 19→ *
 20→ * Layout:  [Left (flex-1)]  [Right]
 21→ *   Left:
 22→ *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 23→ *     Row 2: [pad-left 26px] [secondary · status]
 24→ *   Right:
 25→ *     [+additions -deletions]
 26→ *
 27→ * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 28→ * Secondary line: shows slug when title is primary, otherwise just status info.
 29→ *
 30→ * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 31→ * Idle → no icon (26px indent).
 32→ *
 33→ * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 34→ */
 35→export const WorkspaceItem = React.memo(function WorkspaceItem({
 36→  workspace,
 37→  isActive,
 38→  diffStats,
 39→  onClick,
 40→  onArchive,
 41→  onStatusChange,
 42→}: WorkspaceItemProps) {
 43→  const isInitializing = workspace.state === "initializing";
 44→
 45→  // Hooks must be called unconditionally (React rules of hooks)
 46→  const { duration } = useWorkingDuration({
 47→    status: workspace.session_status,
 48→    latestMessageSentAt: workspace.latest_message_sent_at,
 49→  });
 50→
 51→  const sessionId = workspace.current_session_id;
 52→  const hasUnseenActivity = useUnreadStore(
 53→    (s) => !!sessionId && !!s.unreadSessionIds[sessionId]
 54→  );
 55→
 56→  // Initializing state: non-interactive row with loading animation
 57→  if (isInitializing) {
 58→    const initSecondary = getWorkspaceSecondaryText(workspace);
 59→    return (
 60→      <div className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 61→        <SidebarRow
 62→          variant="workspace"
 63→          isActive={false}
 64→          aria-label="Workspace setting up"
 65→          className="pointer-events-none"
 66→        >
 67→          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
 68→            {/* Row 1: thinking icon + display name */}
 69→            <div className="flex min-w-0 items-center gap-1.5">
 70→              <SidebarRowIconSlot>
 71→                <CircularPixelGrid variant="working" size={14} resolution={8} />
 72→              </SidebarRowIconSlot>
 73→              <span className="text-text-disabled truncate text-base font-normal">
 74→                {getWorkspaceDisplayName(workspace)}
 75→              </span>
 76→            </div>
 77→            {/* Row 2: secondary context · init stage */}
 78→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 79→              {initSecondary && (
 80→                <>
 81→                  <span className="text-text-disabled truncate text-xs">{initSecondary}</span>
 82→                  <span className="text-text-disabled text-xs">·</span>
 83→                </>
 84→              )}
 85→              <span className="text-text-muted shrink-0 text-xs">
 86→                {match(workspace.init_stage)
 87→                  .with("worktree", () => "Creating worktree...")
 88→                  .with("dependencies", () => "Installing dependencies...")
 89→                  .with("hooks", () => "Setting up environment...")
 90→                  .with("session", () => "Finalizing...")
 91→                  .otherwise(() => "Setting up...")}
 92→              </span>
 93→            </div>
 94→          </div>
 95→        </SidebarRow>
 96→      </div>
 97→    );
 98→  }
 99→
100→  const formatTime = (timestamp: string) => {
101→    const date = new Date(timestamp);
102→    const now = new Date();
103→    const diffMs = now.getTime() - date.getTime();
104→    const diffMins = Math.floor(diffMs / 60000);
105→    const diffHours = Math.floor(diffMins / 60);
106→    const diffDays = Math.floor(diffHours / 24);
107→    const diffMonths = Math.floor(diffDays / 30);
108→
109→    if (diffMins < 1) return "now";
110→    if (diffMins < 60) return `${diffMins}m ago`;
111→    if (diffHours < 24) return `${diffHours}h ago`;
112→    if (diffDays < 30) return `${diffDays}d ago`;
113→    return `${diffMonths}mo ago`;
114→  };
115→
116→  const displayStatus = getDisplayStatus(workspace, hasUnseenActivity);
117→  const statusConfig = STATUS_CONFIG[displayStatus];
118→  // Session activity icons take priority over workflow status
119→  const hasSessionIcon =
120→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
121→
122→  const isSetupRunning = workspace.setup_status === "running";
123→  const isSetupFailed = workspace.setup_status === "failed";
124→
125→  const statusTextClass = isSetupFailed
126→    ? "text-accent-red-muted"
127→    : isSetupRunning
128→      ? "text-text-muted"
129→      : match(displayStatus)
130→          .with("working", () => "text-text-tertiary")
131→          .with("unread", () => "text-text-secondary")
132→          .with("error", () => "text-accent-red-muted")
133→          .otherwise(() => "text-text-disabled");
134→
135→  const getStatusText = (): string => {
136→    if (isSetupRunning) return "Installing...";
137→    if (isSetupFailed) return "Setup failed";
138→    if (workspace.state === "archived") return "Archived";
139→    if (!workspace.session_status) return formatTime(workspace.updated_at);
140→
141→    return match(displayStatus)
142→      .with("idle", () => formatTime(workspace.updated_at))
143→      .with("unread", () => {
144→        const sessionStatus = workspace.session_status;
145→        if (sessionStatus === "needs_response" || sessionStatus === "needs_plan_response") {
146→          return "Needs response";
147→        }
148→        return "Done";
149→      })
150→      .with("working", () =>
151→        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
152→      )
153→      .with("error", () => STATUS_CONFIG.error.label)
154→      .otherwise(() => statusConfig.label);
155→  };
156→
157→  const statusText = getStatusText();
158→  const displayName = getWorkspaceDisplayName(workspace);
159→  const secondaryText = getWorkspaceSecondaryText(workspace);
160→  const showStatusDot = Boolean(secondaryText && statusText);
161→
162→  const additions = diffStats?.additions ?? 0;
163→  const deletions = diffStats?.deletions ?? 0;
164→  const hasChanges = additions > 0 || deletions > 0;
165→
166→  const handleArchive = (e: React.MouseEvent) => {
167→    e.stopPropagation();
168→    if (onArchive) {
169→      onArchive(workspace.id);
170→    }
171→  };
172→
173→  const isArchived = workspace.state === "archived";
174→  const canArchive = !isArchived && !!onArchive;
175→  const isActiveState =
176→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
177→
178→  return (
179→    <div>
180→      <SidebarRow
181→        variant="workspace"
182→        isActive={isActive}
183→        role="button"
184→        tabIndex={0}
185→        data-workspace-id={workspace.id}
186→        className="cursor-pointer"
187→        aria-current={isActive ? "page" : undefined}
188→        aria-label={`Workspace ${displayName}`}
189→        onClick={() => onClick(workspace)}
190→        onKeyDown={(e) => {
191→          if (e.key === " ") e.preventDefault();
192→        }}
193→        onKeyUp={(e) => {
194→          if (e.key === "Enter" || e.key === " ") onClick(workspace);
195→        }}
196→      >
197→        {/* Left: rows */}
198→        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
199→          {/* Row 1: icon + display name (title > slug > branch) */}
200→          <div className="flex min-w-0 items-center gap-1.5">
201→            <WorkspaceStatusMenu
202→              currentStatus={workspace.status}
203→              onStatusChange={(status) => onStatusChange?.(workspace.id, status)}
204→            >
205→              <button
206→                type="button"
207→                onClick={(e) => e.stopPropagation()}
208→                className="flex h-5 w-5 shrink-0 items-center justify-center rounded transition-opacity hover:opacity-80"
209→                aria-label={`Status: ${workspace.status}`}
210→              >
211→                {hasSessionIcon ? (
212→                  match(displayStatus)
213→                    .with("working", () => (
214→                      <CircularPixelGrid variant="working" size={14} resolution={8} />
215→                    ))
216→                    .with("error", () => <span className="bg-accent-red h-2 w-2 rounded-full" />)
217→                    .otherwise(() => <span className="bg-accent-gold h-2 w-2 rounded-full" />)
218→                ) : (
219→                  <WorkflowStatusIcon status={workspace.status} size={14} />
220→                )}
221→              </button>
222→            </WorkspaceStatusMenu>
223→            <span
224→              className={cn(
225→                "truncate text-base",
226→                isActive
227→                  ? "text-text-primary font-medium"
228→                  : isActiveState
229→                    ? "text-text-primary font-normal"
230→                    : "text-text-tertiary font-normal"
231→              )}
232→            >
233→              {displayName}
234→            </span>
235→          </div>
236→
237→          {/* Row 2: secondary context · status */}
238→          <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
239→            {secondaryText && (
240→              <span
241→                className={cn(
242→                  "truncate text-xs",
243→                  isActiveState ? "text-text-tertiary" : "text-text-disabled"
244→                )}
245→              >
246→                {secondaryText}
247→              </span>
248→            )}
249→            {showStatusDot && (
250→              <span
251→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
252→              >
253→                ·
254→              </span>
255→            )}
256→            {statusText && (
257→              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
258→                {isSetupRunning && (
259→                  <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />
260→                )}
261→                {statusText}
262→              </span>
263→            )}
264→          </div>
265→        </div>
266→
267→        {/* Right: diff stats */}
268→        {hasChanges ? (
269→          <div
270→            className={cn(
271→              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
272→              canArchive && "group-hover/sidebar-row:opacity-0"
273→            )}
274→          >
275→            {additions > 0 && (
276→              <NumberFlow
277→                value={additions}
278→                prefix="+"
279→                className={isActive ? "text-accent-green" : "text-text-muted"}
280→              />
281→            )}
282→            {deletions > 0 && (
283→              <NumberFlow
284→                value={deletions}
285→                prefix="-"
286→                className={isActive ? "text-accent-red" : "text-text-muted"}
287→              />
288→            )}
289→          </div>
290→        ) : null}
291→
292→        {/* Archive button — hover reveal */}
293→        {canArchive ? (
294→          <button
295→            type="button"
296→            onClick={handleArchive}
297→            aria-label={`Archive workspace ${displayName}`}
298→            title="Archive workspace"
299→            className={cn(
300→              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
301→              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
302→              "group-hover/sidebar-row:opacity-100"
303→            )}
304→          >
305→            <Archive className="h-3.5 w-3.5" />
306→          </button>
307→        ) : null}
308→      </SidebarRow>
309→    </div>
310→  );
311→});
