 10→import { sortByStatusPriority } from "../lib/status";
 11→import type { RepositoryItemProps } from "../model/types";
 12→import { WorkspaceItem } from "./WorkspaceItem";
 13→import { RepoAvatar } from "./RepoAvatar";
 14→import { SidebarRow, SidebarRowMain, SidebarRowIconSlot, SidebarRowRight } from "./SidebarRow";
