 22→/**
 23→ * RepositoryItem — V2: Jony Ive
 24→ *
 25→ * Layout:
 26→ *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 27→ *     └── [+ New workspace]
 28→ *     └── WorkspaceItem[]
 29→ *
 30→ * The repo header uses text-secondary (B0B0B0) 14px medium.
 31→ * Action icons: text-muted (#787878), appear on hover.
 32→ */
 33→export function RepositoryItem({
 34→  repository,
 35→  isCollapsed,
 36→  selectedWorkspaceId,
 37→  onToggleCollapse,
 38→  onWorkspaceClick,
 39→  onNewWorkspace,
 40→  onNewWorkspaceFromGitHub,
 41→  onArchive,
 42→  onStatusChange,
 43→  diffStatsMap,
 44→  sidebarExpanded,
 45→}: RepositoryItemProps) {
 46→  const reduceMotion = useReducedMotion();
 47→  const repoName = getCleanRepoName(repository.repo_name);
 48→
 49→  // Derive unread session IDs for this repo's workspaces (for sort priority).
 50→  // Subscribe only to the relevant session IDs to avoid cross-repo re-renders.
 51→  const repoSessionIds = useMemo(
 52→    () => repository.workspaces.map((w) => w.current_session_id).filter(Boolean) as string[],
 53→    [repository.workspaces]
 54→  );
 55→  const unreadKey = useUnreadStore((s) => {
 56→    let key = "";
 57→    for (const sid of repoSessionIds) {
 58→      if (s.unreadSessionIds[sid]) key += sid + ",";
 59→    }
 60→    return key;
 61→  });
 62→  const unreadSessionIds = useMemo(() => {
 63→    if (!unreadKey) return undefined;
 64→    const ids = new Set<string>();
 65→    for (const sid of unreadKey.split(",")) {
 66→      if (sid) ids.add(sid);
 67→    }
 68→    return ids;
 69→  }, [unreadKey]);
 70→  // Detect the opendevs repo by clean name (works for "opendevs" or "org/opendevs")
 71→  const isOpenDevs = repoName === "opendevs";
 72→  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;
 73→
 74→  return (
 75→    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
 76→      <SidebarMenuItem
 77→        data-state={isCollapsed ? "closed" : "open"}
 78→        className="group/repository-item relative"
 79→      >
 80→        <CollapsibleTrigger asChild>
 81→          <SidebarRow
 82→            variant="repo"
 83→            role="button"
 84→            aria-label={`Toggle ${repoName} workspaces`}
 85→            className="cursor-grab"
 86→          >
 87→            <SidebarRowMain className="gap-2">
 88→              <div className="relative flex-shrink-0">
 89→                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
 90→                  <RepoAvatar repoName={repository.repo_name} />
 91→                </div>
 92→                <ChevronRight
 93→                  className={cn(
 94→                    "absolute inset-0 m-auto h-4 w-4",
 95→                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
 96→                    !isCollapsed && "rotate-90"
 97→                  )}
 98→                />
 99→              </div>
100→              <span className="text-text-secondary truncate text-sm font-medium">{repoName}</span>
101→              {workspaceCount > 0 && (
102→                <span className="text-text-muted text-xs tabular-nums">{workspaceCount}</span>
103→              )}
104→            </SidebarRowMain>
105→            {sidebarExpanded && (
106→              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
107→                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
108→                  <Tooltip>
109→                    <TooltipTrigger asChild>
110→                      <button
111→                        type="button"
112→                        aria-label={`New workspace from PR or branch in ${repoName}`}
113→                        onClick={(e) => {
114→                          e.stopPropagation();
115→                          onNewWorkspaceFromGitHub(repository.repo_id);
116→                        }}
117→                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
118→                      >
119→                        <GitPullRequest className="h-4 w-4" />
120→                      </button>
121→                    </TooltipTrigger>
122→                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
123→                  </Tooltip>
124→                )}
125→                <Tooltip>
126→                  <TooltipTrigger asChild>
127→                    <button
128→                      type="button"
129→                      aria-label={`New workspace in ${repoName}`}
130→                      onClick={(e) => {
131→                        e.stopPropagation();
132→                        onNewWorkspace(repository.repo_id);
133→                      }}
134→                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
135→                    >
136→                      <Plus className="h-4 w-4" />
137→                    </button>
138→                  </TooltipTrigger>
139→                  <TooltipContent side="bottom">New workspace</TooltipContent>
140→                </Tooltip>
141→              </SidebarRowRight>
142→            )}
143→          </SidebarRow>
144→        </CollapsibleTrigger>
145→      </SidebarMenuItem>
146→      <AnimatePresence initial={false}>
147→        {!isCollapsed && (
148→          <m.ul
149→            key="workspace-list"
150→            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
151→            animate={{ height: "auto", opacity: 1 }}
152→            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
153→            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
154→            className="flex min-w-0 flex-col overflow-hidden"
155→          >
156→            {sidebarExpanded &&
157→              (() => {
158→                const sortedWorkspaces = sortByStatusPriority(
159→                  repository.workspaces.filter((w) => w.state !== "archived"),
160→                  unreadSessionIds
161→                );
162→
163→                return (
164→                  <>
165→                    {/* OpenDevs repo gets a special contribution nudge banner */}
166→                    {isOpenDevs && (
167→                      <m.li
168→                        initial={reduceMotion ? false : { opacity: 0, y: -4 }}
169→                        animate={{ opacity: 1, y: 0 }}
170→                        transition={{
171→                          duration: 0.22,
172→                          ease: [0.165, 0.84, 0.44, 1],
173→                          delay: reduceMotion ? 0 : 0.02,
174→                        }}
175→                      >
176→                        <OpenDevsRepositoryBanner
177→                          onNewWorkspace={() => onNewWorkspace(repository.repo_id)}
178→                        />
179→                      </m.li>
180→                    )}
181→
182→                    {sortedWorkspaces.length === 0 && (
183→                      <m.li
184→                        initial={reduceMotion ? false : { opacity: 0, y: -4 }}
185→                        animate={{ opacity: 1, y: 0 }}
186→                        transition={{
187→                          duration: 0.18,
188→                          ease: [0.165, 0.84, 0.44, 1],
189→                          delay: reduceMotion ? 0 : 0.03,
190→                        }}
191→                      >
192→                        <SidebarRow
193→                          variant="action"
194→                          asChild
195→                          onClick={() => onNewWorkspace(repository.repo_id)}
196→                          className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
197→                        >
198→                          <button type="button">
199→                            <SidebarRowMain>
200→                              <SidebarRowIconSlot>
201→                                <Plus className="h-4 w-4" />
202→                              </SidebarRowIconSlot>
203→                              <span className="font-normal">New workspace</span>
204→                            </SidebarRowMain>
205→                          </button>
206→                        </SidebarRow>
207→                      </m.li>
208→                    )}
209→
210→                    {sortedWorkspaces.map((workspace, index) => (
211→                      <m.li
212→                        key={workspace.id}
213→                        initial={reduceMotion ? false : { opacity: 0, y: -4 }}
214→                        animate={{ opacity: 1, y: 0 }}
215→                        transition={{
216→                          duration: 0.18,
217→                          ease: [0.165, 0.84, 0.44, 1],
218→                          delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
219→                        }}
220→                      >
221→                        <WorkspaceItem
222→                          workspace={workspace}
223→                          isActive={workspace.id === selectedWorkspaceId}
224→                          diffStats={diffStatsMap?.[workspace.id]}
225→                          onClick={onWorkspaceClick}
226→                          onArchive={onArchive}
227→                          onStatusChange={onStatusChange}
228→                        />
229→                      </m.li>
230→                    ))}
231→                  </>
232→                );
233→              })()}
234→          </m.ul>
235→        )}
236→      </AnimatePresence>
237→    </Collapsible>
238→  );
239→}
