 58→const ICON_SIZE = "w-3.5 h-3.5";
 59→const EMPTY_CLOSED_TABS: ClosedTab[] = [];
 60→
 61→/** Render tab icon — shows CircularPixelGrid spinner when working, agent logo otherwise. */
 62→function getTabIcon(tab: Tab, isWorking: boolean) {
 63→  if (isWorking) {
 64→    return <CircularPixelGrid variant="generating" size={14} resolution={8} />;
 65→  }
 66→  const LogoComponent = getAgentLogo(tab.data?.agentType || "claude");
 67→  if (LogoComponent) {
 68→    return <LogoComponent className={cn(ICON_SIZE, "flex-shrink-0")} />;
 69→  }
 70→  return null;
 71→}
