 73→function getClosedTabIcon(agentType?: string) {
 74→  const LogoComponent = getAgentLogo(agentType || "claude");
 75→  if (LogoComponent) {
 76→    return <LogoComponent className={cn(ICON_SIZE, "flex-shrink-0")} />;
 77→  }
 78→  return null;
 79→}
