 81→/**
 82→ * MainContentTabBar — tabs-only bar for the chat area.
 83→ * Workspace context (repo, branch, PR actions) moved to WorkspaceHeader.
 84→ *
 85→ * Close rules:
 86→ * - Any tab can be closed as long as at least one tab remains
 87→ * - The close button only appears on hover when there are 2+ tabs
 88→ */
 89→const EMPTY_WORKING_SET = new Set<string>();
 90→
 91→export function MainContentTabBar({
 92→  tabs,
 93→  activeTabId,
 94→  workingSessionIds = EMPTY_WORKING_SET,
 95→  unreadSessionIds = EMPTY_WORKING_SET,
 96→  onTabChange,
 97→  onTabClose,
 98→  onTabAdd,
 99→  onTabReorder,
100→  closedTabs = EMPTY_CLOSED_TABS,
101→  onTabRestore,
102→  onCollapseChatPanel,
103→}: MainContentTabBarProps) {
104→  const [restoreOpen, setRestoreOpen] = useState(false);
105→  const canCloseTabs = tabs.length > 1;
106→
107→  // dnd-kit: 5px distance threshold prevents accidental drags when clicking tabs
108→  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 5 } }));
109→
110→  function handleDragEnd(event: DragEndEvent) {
111→    const { active, over } = event;
112→    if (!over || active.id === over.id || !onTabReorder) return;
113→
114→    const oldIndex = tabs.findIndex((t) => t.id === active.id);
115→    const newIndex = tabs.findIndex((t) => t.id === over.id);
116→    if (oldIndex === -1 || newIndex === -1) return;
117→
118→    onTabReorder(arrayMove(tabs, oldIndex, newIndex));
119→  }
120→
121→  return (
122→    <div className="drag-region chat-tabs-header relative z-20 flex h-10 flex-shrink-0 items-center px-2.5">
123→      <div
124→        role="tablist"
125→        className="scrollbar-hidden relative z-[1] flex min-w-0 flex-1 items-center gap-1.5 overflow-x-auto"
126→      >
127→        <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
128→          <SortableContext items={tabs.map((t) => t.id)} strategy={horizontalListSortingStrategy}>
129→            {tabs.map((tab) => {
130→              const isActive = tab.id === activeTabId;
131→              // Per-tab working status: each tab checks its own session ID
132→              // against the working set (populated by useWorkingSessionIds).
133→              const isWorking = !!tab.data?.sessionId && workingSessionIds.has(tab.data.sessionId);
134→              // Per-tab unread status: show dot when session has unseen activity
135→              const isUnread =
136→                !isActive &&
137→                !isWorking &&
138→                !!tab.data?.sessionId &&
139→                unreadSessionIds.has(tab.data.sessionId);
140→
141→              return (
142→                <SortableTab key={tab.id} id={tab.id}>
143→                  <div
144→                    role="tab"
145→                    aria-selected={isActive}
146→                    tabIndex={0}
147→                    onClick={() => onTabChange(tab.id)}
148→                    onKeyDown={(e) => {
149→                      if (e.key === "Enter" || e.key === " ") {
150→                        e.preventDefault();
151→                        onTabChange(tab.id);
152→                      }
153→                    }}
154→                    className={cn(
155→                      "group relative flex items-center gap-1.5 overflow-hidden",
156→                      "h-7 max-w-[200px] min-w-[80px] rounded-lg px-2",
157→                      "cursor-pointer text-base font-normal",
158→                      "transition-colors duration-150",
159→                      isActive
160→                        ? "bg-bg-raised text-text-secondary"
161→                        : isUnread
162→                          ? "text-text-secondary"
163→                          : "text-text-muted hover:text-text-tertiary"
164→                    )}
165→                  >
166→                    {getTabIcon(tab, isWorking)}
167→
168→                    <div className="min-w-0 flex-1">
169→                      <span className="block truncate">{tab.label}</span>
170→                    </div>
171→
172→                    {/* Unread dot — visible on inactive tabs with unseen activity */}
173→                    {isUnread && (
174→                      <span className="bg-accent-gold h-1.5 w-1.5 flex-shrink-0 rounded-full" />
175→                    )}
176→
177→                    {/* Close button — overlays right edge on hover, only when 2+ tabs */}
178→                    {onTabClose && canCloseTabs && (
179→                      <div
180→                        className={cn(
181→                          "absolute inset-y-0 right-0 flex items-center pr-1.5 pl-4",
182→                          "opacity-0 transition-opacity duration-150 group-hover:opacity-100",
183→                          isActive
184→                            ? "from-bg-raised bg-gradient-to-l from-50% to-transparent"
185→                            : "from-bg-surface group-hover:from-bg-surface bg-gradient-to-l from-50% to-transparent"
186→                        )}
187→                      >
188→                        <button
189→                          type="button"
190→                          onClick={(e) => {
191→                            e.stopPropagation();
192→                            onTabClose(tab.id);
193→                          }}
194→                          className={cn(
195→                            "flex h-4 w-4 items-center justify-center rounded-sm",
196→                            "transition-colors duration-150",
197→                            "hover:bg-bg-muted"
198→                          )}
199→                          aria-label={`Close ${tab.label} tab`}
200→                        >
201→                          <X className="h-2.5 w-2.5" />
202→                        </button>
203→                      </div>
204→                    )}
205→                  </div>
206→                </SortableTab>
207→              );
208→            })}
209→          </SortableContext>
210→        </DndContext>
211→
212→        {/* New tab button — stays adjacent to tabs */}
213→        {onTabAdd && (
214→          <Tooltip delayDuration={200}>
215→            <TooltipTrigger asChild>
216→              <button
217→                type="button"
218→                aria-label="New chat tab"
219→                onClick={() => onTabAdd?.()}
220→                className={cn(
221→                  "flex items-center justify-center",
222→                  "h-7 flex-shrink-0 rounded-lg px-1.5",
223→                  "text-text-disabled hover:text-text-muted",
224→                  "transition-colors duration-150"
225→                )}
226→              >
227→                <Plus className="h-4 w-4" />
228→              </button>
229→            </TooltipTrigger>
230→            <TooltipContent side="bottom">
231→              <div className="flex items-center gap-3">
232→                <span className="text-xs">New chat</span>
233→                <TooltipKbd>⌘T</TooltipKbd>
234→              </div>
235→            </TooltipContent>
236→          </Tooltip>
237→        )}
238→      </div>
239→
240→      {/* History button — pinned far right, outside scrollable area */}
241→      {onTabRestore && closedTabs.length > 0 && (
242→        <Popover open={restoreOpen} onOpenChange={setRestoreOpen}>
243→          <Tooltip delayDuration={200}>
244→            <TooltipTrigger asChild>
245→              <PopoverTrigger asChild>
246→                <button
247→                  type="button"
248→                  aria-label="Restore closed session"
249→                  className={cn(
250→                    "flex items-center justify-center",
251→                    "h-7 flex-shrink-0 rounded-lg px-1.5",
252→                    "text-text-disabled hover:text-text-muted",
253→                    "transition-colors duration-150"
254→                  )}
255→                >
256→                  <History className="h-3.5 w-3.5" />
257→                </button>
258→              </PopoverTrigger>
259→            </TooltipTrigger>
260→            {!restoreOpen && (
261→              <TooltipContent side="bottom">
262→                <p className="text-xs">Restore closed session (⌘⇧T)</p>
263→              </TooltipContent>
264→            )}
265→          </Tooltip>
266→          <PopoverContent align="end" sideOffset={6} className="w-56 p-1">
267→            <p className="text-text-muted px-2 py-1.5 text-xs font-medium">Recently closed</p>
268→            <div className="max-h-48 overflow-y-auto">
269→              {closedTabs.map((ct, i) => (
270→                <button
271→                  key={`${ct.sessionId}-${i}`}
272→                  type="button"
273→                  onClick={() => {
274→                    onTabRestore(ct);
275→                    setRestoreOpen(false);
276→                  }}
277→                  className={cn(
278→                    "flex w-full items-center gap-2 rounded-sm px-2 py-1.5",
279→                    "text-text-secondary text-left text-base",
280→                    "transition-colors duration-150",
281→                    "hover:bg-bg-raised"
282→                  )}
283→                >
284→                  {getClosedTabIcon(ct.agentType)}
285→                  <span className="min-w-0 flex-1 truncate">{ct.label}</span>
286→                </button>
287→              ))}
288→            </div>
289→          </PopoverContent>
290→        </Popover>
291→      )}
292→
293→      {/* Collapse chat panel — pinned to right edge of tab bar */}
294→      {onCollapseChatPanel && (
295→        <Tooltip delayDuration={200}>
296→          <TooltipTrigger asChild>
297→            <button
298→              type="button"
299→              aria-label="Collapse chat panel"
300→              onClick={onCollapseChatPanel}
301→              className="text-text-disabled hover:text-text-secondary hover:bg-bg-overlay ml-1 flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-lg transition-colors duration-200 ease-out"
302→            >
303→              <PanelLeftClose className="h-4 w-4" />
304→            </button>
305→          </TooltipTrigger>
306→          <TooltipContent side="bottom">
307→            <div className="flex items-center gap-3">
308→              <span className="text-xs">Collapse chat</span>
309→              <TooltipKbd>⌘\</TooltipKbd>
310→            </div>
311→          </TooltipContent>
312→        </Tooltip>
313→      )}
314→    </div>
315→  );
316→}
