  7→
  8→import { useMemo, useCallback } from "react";
  9→import type { Dispatch, SetStateAction } from "react";
 10→import { SessionPanel } from "@/features/session";
 11→import type { SessionPanelRef } from "@/features/session";
 12→import { useWorkingSessionIds } from "@/features/session/api/session.queries";
 13→import { useUnreadStore, unreadActions } from "@/features/session/store/unreadStore";
 14→import { WorkspaceEmptyState } from "@/features/session/ui/WorkspaceEmptyState";
 15→import { MainContentTabBar } from "@/features/workspace";
 16→import type { Workspace } from "@/shared/types";
 17→import { useChatTabs } from "./useChatTabs";
 18→
 19→interface ChatAreaProps {
 20→  workspace: Workspace;
 21→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 22→  onCreatePRHandlerChange: (handler: (() => void) | null) => void;
 23→  onSendAgentMessageHandlerChange: Dispatch<
 24→    SetStateAction<((text: string) => Promise<void>) | null>
 25→  >;
 26→  onCollapseChatPanel?: () => void;
 27→}
 28→
 29→export function ChatArea({
 30→  workspace,
 31→  workspaceChatPanelRef,
 32→  onCreatePRHandlerChange,
 33→  onSendAgentMessageHandlerChange,
 34→  onCollapseChatPanel,
 35→}: ChatAreaProps) {
 36→  const {
 37→    tabs,
 38→    activeTabId,
 39→    activeTab,
 40→    closedTabs,
 41→    handleTabChange,
 42→    handleTabClose,
 43→    handleTabAdd,
 44→    handleTabReorder,
 45→    handleTabRestore,
 46→    updateChatTabAgentType,
 47→    markChatTabStarted,
 48→  } = useChatTabs({
 49→    workspaceId: workspace.id,
 50→    activeSessionId: workspace.current_session_id,
 51→  });
 52→
 53→  // Resolve sessionId: tab's own session, falling back to workspace's active session
 54→  const tabSessionId = activeTab?.data?.sessionId || workspace.current_session_id;
 55→
 56→  // Per-tab working status: subscribes to each chat tab's session detail cache
 57→  // so each tab's spinner reflects its own session's status (not the workspace's
 58→  // single session_status which breaks with multiple tabs).
 59→  const chatSessionIds = useMemo(
 60→    () => tabs.filter((t) => t.data?.sessionId).map((t) => t.data!.sessionId!),
 61→    [tabs]
 62→  );
 63→  const workingSessionIds = useWorkingSessionIds(chatSessionIds);
 64→
 65→  // Unread tracking: read the full map and filter to this workspace's sessions.
 66→  // The store is small (one key per recently-finished session) so this is fine.
 67→  const unreadMap = useUnreadStore((s) => s.unreadSessionIds);
 68→  const unreadSessionIds = useMemo(() => {
 69→    const ids = new Set<string>();
 70→    for (const sid of chatSessionIds) {
 71→      if (unreadMap[sid]) ids.add(sid);
 72→    }
 73→    return ids;
 74→  }, [chatSessionIds, unreadMap]);
 75→
 76→  // Wrap tab change to mark the newly-active session as read inline
 77→  const handleTabChangeWithRead = useCallback(
 78→    (tabId: string) => {
 79→      const tab = tabs.find((t) => t.id === tabId);
 80→      if (tab?.data?.sessionId) {
 81→        unreadActions.markRead(tab.data.sessionId);
 82→      }
 83→      handleTabChange(tabId);
 84→    },
 85→    [tabs, handleTabChange]
 86→  );
 87→
 88→  return (
 89→    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
 90→      <MainContentTabBar
 91→        tabs={tabs}
 92→        activeTabId={activeTabId}
 93→        workingSessionIds={workingSessionIds}
 94→        unreadSessionIds={unreadSessionIds}
 95→        onTabChange={handleTabChangeWithRead}
 96→        onTabClose={handleTabClose}
 97→        onTabAdd={handleTabAdd}
 98→        onTabReorder={handleTabReorder}
 99→        closedTabs={closedTabs}
100→        onTabRestore={handleTabRestore}
101→        onCollapseChatPanel={onCollapseChatPanel}
102→      />
103→
104→      <div className="flex min-h-0 flex-1 flex-col overflow-hidden">
105→        {tabSessionId && (
106→          <SessionPanel
107→            key={tabSessionId}
108→            ref={workspaceChatPanelRef}
109→            sessionId={tabSessionId}
110→            workspaceId={workspace.id}
111→            workspacePath={workspace.workspace_path}
112→            workspaceRepoName={workspace.repo_name}
113→            workspaceParentBranch={workspace.git_target_branch}
114→            workspaceDefaultBranch={workspace.git_default_branch}
115→            isFirstSession={workspace.latest_message_sent_at === null}
116→            embedded={true}
117→            initialModel={activeTab?.data?.initialModel}
118→            onAgentTypeChange={(agentType) =>
119→              activeTab && updateChatTabAgentType(activeTab.id, agentType)
120→            }
121→            onSessionStarted={() => activeTab && markChatTabStarted(activeTab.id)}
122→            onOpenNewTab={handleTabAdd}
123→            onCreatePR={(handler) => onCreatePRHandlerChange(() => handler)}
124→            onSendAgentMessage={(handler) => onSendAgentMessageHandlerChange(() => handler)}
125→          />
126→        )}
127→
128→        {/* Workspace still initializing — show the same empty state with init progress */}
129→        {!tabSessionId && (
130→          <WorkspaceEmptyState
131→            repoName={workspace.repo_name}
132→            parentBranch={workspace.git_target_branch}
133→            isFirstSession={true}
134→            initializing={workspace.state === "initializing"}
135→            initStep={workspace.init_stage}
136→          />
137→        )}
138→      </div>
139→    </div>
140→  );
141→}
