 50→/**
 51→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 52→ * Must be rendered inside SidebarProvider to access sidebar open state.
 53→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 54→ */
 55→function SidebarResizeHandle({
 56→  onSizeChange,
 57→  onDraggingChange,
 58→}: {
 59→  onSizeChange: (size: number | null) => void;
 60→  onDraggingChange: (dragging: boolean) => void;
 61→}) {
 62→  const { open } = useSidebar();
 63→
 64→  const { handleProps, isDragging } = useResizeHandle({
 65→    onSizeChange,
 66→    enabled: open,
 67→    direction: "horizontal",
 68→    mode: "primary",
 69→    minPrimarySize: 200,
 70→    minSecondarySize: 400,
 71→  });
 72→
 73→  // Notify parent of drag state changes to disable sidebar transitions
 74→  useEffect(() => {
 75→    onDraggingChange(isDragging);
 76→  }, [isDragging, onDraggingChange]);
 77→
 78→  if (!open) return null;
 79→
 80→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 81→}
