43→function isUserViewingSession(workspaceId: string, sessionId: string): boolean {
44→  const selectedWorkspaceId = useWorkspaceStore.getState().selectedWorkspaceId;
45→  if (selectedWorkspaceId !== workspaceId) return false;
46→
47→  const layout = workspaceLayoutActions.getLayout(workspaceId);
48→  // If no persisted active tab, the workspace's current_session_id is shown
49→  return layout.activeChatTabSessionId === sessionId || !layout.activeChatTabSessionId;
50→}
