// Detect session + setup transitions from the query cache.
// Two query types are watched:
// 1. ["workspaces", "by-repo"] — workspace-level status (current_session_id only)
// 2. ["sessions", "detail", id] — individual session status (covers all tabs)
const unsubscribe = queryClient.getQueryCache().subscribe((event) => {
  if (event.type !== "updated" || !event.query.queryKey[0]) return;

  const key = event.query.queryKey;

  // --- Individual session detail updates (covers non-current sessions in tabs) ---
  if (key[0] === "sessions" && key[1] === "detail" && typeof key[2] === "string") {
    const session = event.query.state.data as Session | undefined;
    if (!session) return;

    const sessionId = key[2];
    const status = session.status;
    const prevStatus = prevStatusMap.current.get(sessionId);
    prevStatusMap.current.set(sessionId, status);

    if (
      prevStatus === "working" &&
      prevStatus !== status &&
      (status === "idle" || status === "error" || status === "needs_response" || status === "needs_plan_response")
    ) {
      const isViewing = checkIsViewingSession(session.workspace_id, sessionId);
      if (!isViewing) {
        unreadActions.markUnread(sessionId);
      }
    }
    return;
  }

  if (key[0] !== "workspaces" || key[1] !== "by-repo") return;

