// Mark sessions as unread when they stop working and aren't the active tab.
// On first mount, we seed with all started sessions so we catch sessions
// that finished while this workspace wasn't selected.
const activeSessionId = activeTab?.data?.sessionId;
const prevWorkingRef = useRef<Set<string> | null>(null);
useEffect(() => {
  if (prevWorkingRef.current === null) {
    // First mount: treat all started sessions as "was working"
    const started = new Set<string>();
    for (const t of tabs) {
      if (t.data?.hasStarted && t.data.sessionId) started.add(t.data.sessionId);
    }
    prevWorkingRef.current = started;
  }
  const prev = prevWorkingRef.current;
  prevWorkingRef.current = workingSessionIds;
  for (const sid of prev) {
    if (!workingSessionIds.has(sid) && sid !== activeSessionId) {
      unreadActions.markUnread(sid);
    }
  }
}, [workingSessionIds, activeSessionId, tabs]);

