 47→/**
 48→ * Fetch session details — fully WS-driven, no polling.
 49→ *
 50→ * Updates come from WS subscription: backend pushes q:snapshot on
 51→ * session:status, session:updated, and session:message notifications.
 52→ * HTTP queryFn is fallback for initial load before WS connects.
 53→ */
 54→export function useSession(sessionId: string | null) {
 55→  useQuerySubscription("session", {
 56→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 57→    params: { sessionId: sessionId || "" },
 58→    enabled: !!sessionId,
 59→  });
 60→
 61→  return useQuery({
 62→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 63→    queryFn: () => SessionService.fetchById(sessionId!),
 64→    enabled: !!sessionId,
 65→    staleTime: Infinity,
 66→    refetchOnWindowFocus: false,
 67→  });
 68→}
 69→
 70→/**
 71→ * Subscribe to per-session working status for multiple sessions at once.
 72→ * Used by the tab bar to show per-tab spinners correctly.
 73→ *
 74→ * The workspace's single `session_status` field breaks with multiple tabs —
 75→ * it gets overwritten by whichever session's event fires last. This hook
 76→ * subscribes to each session's detail cache reactively so tab spinners
 77→ * reflect each session's actual status.
 78→ *
 79→ * No extra HTTP fetches when data is already in cache (populated by
 80→ * the "session" WS subscription via q:snapshot on status changes).
 81→ */
 82→export function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 83→  const queries = useQueries({
 84→    queries: sessionIds.map((id) => ({
 85→      queryKey: queryKeys.sessions.detail(id),
 86→      queryFn: () => SessionService.fetchById(id),
 87→      staleTime: 30_000,
 88→      select: (data: Session): SessionStatus => data.status,
 89→    })),
 90→  });
 91→
 92→  // Derive working IDs from query results. useMemo deps use `queries`
 93→  // directly — React Compiler requires it. The select: data.status
 94→  // ensures queries only change identity when a status actually changes.
 95→  return useMemo(() => {
 96→    const ids = new Set<string>();
 97→    sessionIds.forEach((id, i) => {
 98→      if (queries[i]?.data === "working") ids.add(id);
 99→    });
100→    return ids;
101→  }, [queries, sessionIds]);
102→}
103→
104→/**
105→ * Fetch messages for a session — fully WS-driven.
106→ *
107→ * WS subscription pushes q:delta frames with new messages since last cursor.
108→ * mergeMessageDelta handles the PaginatedMessages shape, deduplication,
109→ * and optimistic placeholder cleanup.
110→ * HTTP queryFn is fallback for initial load before WS connects.
111→ */
112→export function useMessages(sessionId: string | null) {
113→  useQuerySubscription("messages", {
114→    queryKey: queryKeys.sessions.messages(sessionId || ""),
115→    params: { sessionId: sessionId || "" },
116→    enabled: !!sessionId,
117→    mergeDelta: mergeMessageDelta,
118→  });
119→
120→  const query = useQuery({
121→    queryKey: queryKeys.sessions.messages(sessionId || ""),
122→    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
123→    enabled: !!sessionId,
124→    refetchInterval: false,
125→    staleTime: Infinity,
126→    refetchOnWindowFocus: false,
127→  });
128→
129→  return query;
130→}
131→
132→/**
133→ * Combined hook for session + messages + status
134→ * Replaces the complex useMessages hook
135→ */
136→export function useSessionWithMessages(sessionId: string | null) {
137→  const sessionQuery = useSession(sessionId);
138→  const messagesQuery = useMessages(sessionId);
139→
140→  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
141→  const messages = messagesQuery.data?.messages ?? [];
142→  const hasOlder = messagesQuery.data?.has_older ?? false;
143→
144→  // Parse content helper — delegates to pure function in lib/contentParser.ts
145→  // Memoized to prevent Context cascade re-renders
146→  const parseContent = useCallback(
147→    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
148→    []
149→  );
150→
151→  // Build tool result map and parent_tool_use_id map in a single pass.
152→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
153→    const resultMap = new Map();
154→    const parentMap = new Map<string, string>();
155→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
156→
157→    messages.forEach((msg: Message) => {
158→      if (msg.parent_tool_use_id) {
159→        parentMap.set(msg.id, msg.parent_tool_use_id);
160→      }
161→
162→      const blocks = parseContent(msg.content);
163→      if (Array.isArray(blocks)) {
164→        blocks.filter(isToolResultBlock).forEach((block) => {
165→          resultMap.set(block.tool_use_id, block);
166→        });
167→      }
168→    });
169→
170→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
171→  }, [messages, parseContent]);
172→
173→  // Group subagent messages by their parent Task tool_use_id
174→  const subagentMessages = useMemo(() => {
175→    const map = new Map<string, Message[]>();
176→    if (!messages.length) return map;
177→
178→    messages.forEach((msg: Message) => {
179→      const parentId = parentToolUseMap.get(msg.id);
180→      if (parentId) {
181→        if (!map.has(parentId)) map.set(parentId, []);
182→        map.get(parentId)!.push(msg);
183→      }
184→    });
185→
186→    return map;
187→  }, [messages, parentToolUseMap]);
188→
189→  // Get latest user message's sent_at for duration tracking
190→  const latestMessageSentAt = useMemo(() => {
191→    if (!messages.length) return null;
192→
193→    // Find the latest user message
194→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
195→
196→    return latestUserMessage?.sent_at || null;
197→  }, [messages]);
198→
199→  return {
200→    session: sessionQuery.data,
201→    messages,
202→    hasOlder,
203→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
204→    latestMessageSentAt,
205→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
206→    error: sessionQuery.error || messagesQuery.error,
207→    parseContent,
208→    toolResultMap,
209→    parentToolUseMap,
210→    subagentMessages,
211→  };
212→}
213→
214→/**
215→ * Load older messages (scroll-up pagination).
216→ * Prepends older messages to the cache while preserving has_newer from current cache.
217→ */
218→export function useLoadOlderMessages() {
219→  const queryClient = useQueryClient();
220→
221→  return useMutation({
222→    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
223→      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
224→
225→    onSuccess: (olderPage, { sessionId }) => {
226→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
227→        if (!old) return olderPage;
228→        // Deduplicate by id (shouldn't happen, but safety first)
229→        const existingIds = new Set(old.messages.map((m) => m.id));
230→        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
231→        return {
232→          messages: [...newMessages, ...old.messages],
233→          has_older: olderPage.has_older,
234→          has_newer: old.has_newer,
235→        };
236→      });
237→    },
238→  });
239→}
240→
241→/**
242→ * Send message mutation with optimistic update
243→ *
244→ * Shows user message immediately in the chat while request is in flight.
245→ * The optimistic message has a temporary ID that gets replaced on refetch.
246→ */
247→export function useSendMessage() {
248→  const queryClient = useQueryClient();
249→
250→  return useMutation({
251→    mutationFn: async ({
252→      sessionId,
253→      content,
254→      model,
255→      cwd,
256→      agentType,
257→      permissionMode,
258→    }: {
259→      sessionId: string;
260→      content: string;
261→      model?: string;
262→      cwd?: string;
263→      agentType?: RuntimeAgentType;
264→      permissionMode?: string;
265→    }): Promise<Message | void> => {
266→      // Send message via WS command: backend saves user message to DB,
267→      // forwards to agent-server, and pushes q:delta to subscribers.
268→      if (cwd) {
269→        if (!isConnected()) await connect();
270→        const ack = await sendCommand("sendMessage", {
271→          sessionId,
272→          content,
273→          model,
274→          cwd,
275→          agentType: agentType || "claude",
276→          permissionMode,
277→        });
278→        if (!ack.accepted) {
279→          throw new Error(ack.error || "Agent rejected the query");
280→        }
281→        // No return value needed — WS q:delta handles message reconciliation.
282→        return;
283→      }
284→      // Gateway/web fallback: HTTP POST to backend
285→      return SessionService.sendMessage(sessionId, content, model);
286→    },
287→
288→    // Optimistic update: show user message immediately.
289→    // Status indicators (tab spinner, sidebar) are updated by the workspaces
290→    // WS subscription — the sidecar notifies the backend, which pushes fresh
291→    // workspace snapshots within ~50ms.
292→    onMutate: async ({ sessionId, content, model }) => {
293→      await queryClient.cancelQueries({
294→        queryKey: queryKeys.sessions.messages(sessionId),
295→      });
296→
297→      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
298→        queryKeys.sessions.messages(sessionId)
299→      );
300→
301→      // Snapshot workspace-by-repo cache before optimistic update so we can
302→      // restore the exact prior status on error (instead of hardcoding "idle").
303→      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
304→        queryKey: ["workspaces", "by-repo"],
305→      });
306→
307→      // Create optimistic user message
308→      const optimisticId =
309→        typeof crypto !== "undefined" && "randomUUID" in crypto
310→          ? `optimistic-${crypto.randomUUID()}`
311→          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
312→
313→      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
314→      let optimisticContentJson: string;
315→      try {
316→        const parsed = JSON.parse(content);
317→        if (Array.isArray(parsed)) {
318→          optimisticContentJson = JSON.stringify(parsed);
319→        } else {
320→          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
321→        }
322→      } catch {
323→        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
324→      }
325→
326→      const optimisticMessage: Message = {
327→        id: optimisticId,
328→        session_id: sessionId,
329→        seq: Number.MAX_SAFE_INTEGER,
330→        role: "user",
331→        content: optimisticContentJson,
332→        sent_at: new Date().toISOString(),
333→        model: model ?? null,
334→      };
335→
336→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
337→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
338→        return produce(old, (draft) => {
339→          draft.messages.push(optimisticMessage);
340→        });
341→      });
342→
343→      // Optimistically set workspace status to "working" in sidebar cache.
344→      // Handles the startup race where the first IPC event arrives before
345→      // the workspace list has loaded (cache empty → event matching fails).
346→      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
347→        if (!old) return old;
348→        return old.map((group) => ({
349→          ...group,
350→          workspaces: group.workspaces.map((ws) =>
351→            ws.current_session_id === sessionId
352→              ? { ...ws, session_status: "working" as SessionStatus }
353→              : ws
354→          ),
355→        }));
356→      });
357→
358→      return { previousMessages, previousWorkspaceByRepo };
359→    },
360→
361→    onError: (_err, variables, context) => {
362→      // If the error is a WS connectivity issue, escalate the connection state
363→      // immediately. The WS client produces three distinct error messages:
364→      //   "WebSocket not connected"     — socket already down before send
365→      //   "WebSocket disconnected"      — connection dropped mid-flight
366→      //   "WebSocket connection failed" — connect() rejected (initial open failed)
367→      if (_err instanceof Error) {
368→        const msg = _err.message.toLowerCase();
369→        if (
370→          msg.includes("not connected") ||
371→          msg.includes("disconnected") ||
372→          msg.includes("connection failed")
373→        ) {
374→          emitSendAttemptFailed();
375→        }
376→      }
377→      // Roll back optimistic message
378→      if (context?.previousMessages) {
379→        queryClient.setQueryData(
380→          queryKeys.sessions.messages(variables.sessionId),
381→          context.previousMessages
382→        );
383→      } else {
384→        // No snapshot (first send on empty cache) — invalidate to clear the ghost optimistic message
385→        queryClient.invalidateQueries({
386→          queryKey: queryKeys.sessions.messages(variables.sessionId),
387→        });
388→      }
389→      // Roll back optimistic workspace status from snapshot
390→      if (context?.previousWorkspaceByRepo?.length) {
391→        context.previousWorkspaceByRepo.forEach(([key, data]) => {
392→          queryClient.setQueryData(key, data);
393→        });
394→      } else {
395→        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
396→      }
397→    },
398→
399→    onSettled: async (_, error, variables) => {
400→      if (!error) {
401→        const hasImages = (() => {
402→          try {
403→            const parsed = JSON.parse(variables.content);
404→            return (
405→              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
406→            );
407→          } catch {
408→            return false;
409→          }
410→        })();
411→        const session = queryClient.getQueryData<Session>(
412→          queryKeys.sessions.detail(variables.sessionId)
413→        );
414→        track("session_message_sent", {
415→          session_id: variables.sessionId,
416→          has_images: hasImages,
417→          model: variables.model,
418→          agent_type: session?.agent_type,
419→          message_count: session?.message_count,
420→          context_used_percent: session?.context_used_percent,
421→        });
422→      }
423→      // No incrementalFetchAndMerge needed — WS q:delta handles reconciliation.
424→      // The optimistic message stays visible until the delta arrives with the real message.
425→    },
426→  });
427→}
428→
429→/**
430→ * Stop session mutation
431→ */
432→export function useStopSession() {
433→  const queryClient = useQueryClient();
434→
435→  return useMutation({
436→    mutationFn: (sessionId: string) => SessionService.stop(sessionId),
437→    onSuccess: (_, sessionId) => {
438→      const session = queryClient.getQueryData<Session>(queryKeys.sessions.detail(sessionId));
439→      track("session_stopped", {
440→        session_id: sessionId,
441→        agent_type: session?.agent_type,
442→      });
443→      // Immediate invalidation for snappy UI feedback.
444→      // Backend also pushes via WS q:invalidate. React Query deduplicates.
445→      queryClient.invalidateQueries({
446→        queryKey: queryKeys.sessions.detail(sessionId),
447→      });
448→      queryClient.invalidateQueries({
449→        queryKey: queryKeys.workspaces.all,
450→      });
451→    },
452→  });
453→}
454→
455→/**
456→ * Create a new session for a workspace.
457→ * Used when user opens a new chat tab (Cmd+T).
458→ * Backend creates the session and updates workspace.current_session_id.
459→ */
460→export function useCreateSession() {
461→  const queryClient = useQueryClient();
462→
463→  return useMutation({
464→    mutationFn: (workspaceId: string) => SessionService.createSession(workspaceId),
465→    onSuccess: (newSession, workspaceId) => {
466→      track("session_created", {
467→        workspace_id: workspaceId,
468→        agent_type: newSession?.agent_type,
469→        model: newSession?.model,
470→      });
471→      // Immediate invalidation for snappy UI feedback.
472→      // Backend also pushes via WS q:invalidate. React Query deduplicates.
473→      queryClient.invalidateQueries({
474→        queryKey: queryKeys.workspaces.all,
475→      });
476→      queryClient.invalidateQueries({
477→        queryKey: queryKeys.workspaces.detail(workspaceId),
478→      });
479→      queryClient.invalidateQueries({
480→        queryKey: queryKeys.sessions.byWorkspace(workspaceId),
481→      });
482→    },
483→  });
484→}
