import React from "react";
import { match } from "ts-pattern";
import { Archive, Loader2 } from "lucide-react";
import NumberFlow from "@number-flow/react";

import { cn } from "@/shared/lib/utils";
import { useWorkingDuration, formatDuration } from "@/shared/hooks";
import { CircularPixelGrid } from "@/features/session/ui/CircularPixelGrid";
import { useUnreadStore } from "@/features/session/store/unreadStore";
import { useWorkspaceLayoutStore } from "@/features/workspace/store/workspaceLayoutStore";
import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
import { getWorkspaceDisplayName, getWorkspaceSecondaryText } from "../lib/utils";
import type { WorkspaceItemProps } from "../model/types";
import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
import { WorkflowStatusIcon } from "./WorkflowStatusIcon";
import { WorkspaceStatusMenu } from "./WorkspaceStatusMenu";

/**
 * WorkspaceItem — Sidebar workspace row
 *
 * Layout:  [Left (flex-1)]  [Right]
 *   Left:
 *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 *     Row 2: [pad-left 26px] [secondary · status]
 *   Right:
 *     [+additions -deletions]
 *
 * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 * Secondary line: shows slug when title is primary, otherwise just status info.
 *
 * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 * Idle → no icon (26px indent).
 *
 * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 */
export const WorkspaceItem = React.memo(function WorkspaceItem({
  workspace,
  isActive,
  diffStats,
  onClick,
  onArchive,
  onStatusChange,
}: WorkspaceItemProps) {
  const isInitializing = workspace.state === "initializing";

  // Hooks must be called unconditionally (React rules of hooks)
  const { duration } = useWorkingDuration({
    status: workspace.session_status,
    latestMessageSentAt: workspace.latest_message_sent_at,
  });

  // Check all sessions in this workspace's tabs for unseen activity,
  // not just current_session_id — the user may have multiple tabs open.
  const tabSessionIds = useWorkspaceLayoutStore(
    (s) => s.layouts[workspace.id]?.chatTabSessionIds
  );
  const hasUnseenActivity = useUnreadStore((s) => {
    const ids = tabSessionIds?.length ? tabSessionIds : workspace.current_session_id ? [workspace.current_session_id] : [];
    return ids.some((sid) => s.unreadSessionIds[sid]);
  });

  // Initializing state: non-interactive row with loading animation
  if (isInitializing) {
    const initSecondary = getWorkspaceSecondaryText(workspace);
    return (
      <div className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
        <SidebarRow
          variant="workspace"
          isActive={false}
          aria-label="Workspace setting up"
          className="pointer-events-none"
        >
          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
            {/* Row 1: thinking icon + display name */}
            <div className="flex min-w-0 items-center gap-1.5">
              <SidebarRowIconSlot>
                <CircularPixelGrid variant="working" size={14} resolution={8} />
              </SidebarRowIconSlot>
              <span className="text-text-disabled truncate text-base font-normal">
                {getWorkspaceDisplayName(workspace)}
              </span>
            </div>
            {/* Row 2: secondary context · init stage */}
            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
              {initSecondary && (
                <>
                  <span className="text-text-disabled truncate text-xs">{initSecondary}</span>
                  <span className="text-text-disabled text-xs">·</span>
                </>
              )}
              <span className="text-text-muted shrink-0 text-xs">
                {match(workspace.init_stage)
                  .with("worktree", () => "Creating worktree...")
                  .with("dependencies", () => "Installing dependencies...")
                  .with("hooks", () => "Setting up environment...")
                  .with("session", () => "Finalizing...")
                  .otherwise(() => "Setting up...")}
              </span>
            </div>
          </div>
        </SidebarRow>
      </div>
    );
  }

  const formatTime = (timestamp: string) => {
    const date = new Date(timestamp);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMins / 60);
    const diffDays = Math.floor(diffHours / 24);
    const diffMonths = Math.floor(diffDays / 30);

    if (diffMins < 1) return "now";
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 30) return `${diffDays}d ago`;
    return `${diffMonths}mo ago`;
  };

  const displayStatus = getDisplayStatus(workspace, hasUnseenActivity);
  const statusConfig = STATUS_CONFIG[displayStatus];
  // Session activity icons take priority over workflow status
  const hasSessionIcon =
    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";

  const isSetupRunning = workspace.setup_status === "running";
  const isSetupFailed = workspace.setup_status === "failed";

  const statusTextClass = isSetupFailed
    ? "text-accent-red-muted"
    : isSetupRunning
      ? "text-text-muted"
      : match(displayStatus)
          .with("working", () => "text-text-tertiary")
          .with("unread", () => "text-text-secondary")
          .with("error", () => "text-accent-red-muted")
          .otherwise(() => "text-text-disabled");

  const getStatusText = (): string => {
    if (isSetupRunning) return "Installing...";
    if (isSetupFailed) return "Setup failed";
    if (workspace.state === "archived") return "Archived";
    if (!workspace.session_status) return formatTime(workspace.updated_at);

    return match(displayStatus)
      .with("idle", () => formatTime(workspace.updated_at))
      .with("unread", () => {
        const sessionStatus = workspace.session_status;
        if (sessionStatus === "needs_response" || sessionStatus === "needs_plan_response") {
          return "Needs response";
        }
        return "Done";
      })
      .with("working", () =>
        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
      )
      .with("error", () => STATUS_CONFIG.error.label)
      .otherwise(() => statusConfig.label);
  };

  const statusText = getStatusText();
  const displayName = getWorkspaceDisplayName(workspace);
  const secondaryText = getWorkspaceSecondaryText(workspace);
  const showStatusDot = Boolean(secondaryText && statusText);

  const additions = diffStats?.additions ?? 0;
  const deletions = diffStats?.deletions ?? 0;
  const hasChanges = additions > 0 || deletions > 0;

  const handleArchive = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onArchive) {
      onArchive(workspace.id);
    }
  };

  const isArchived = workspace.state === "archived";
  const canArchive = !isArchived && !!onArchive;
  const isActiveState =
    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";

  return (
    <div>
      <SidebarRow
        variant="workspace"
        isActive={isActive}
        role="button"
        tabIndex={0}
        data-workspace-id={workspace.id}
        className="cursor-pointer"
        aria-current={isActive ? "page" : undefined}
        aria-label={`Workspace ${displayName}`}
        onClick={() => onClick(workspace)}
        onKeyDown={(e) => {
          if (e.key === " ") e.preventDefault();
        }}
        onKeyUp={(e) => {
          if (e.key === "Enter" || e.key === " ") onClick(workspace);
        }}
      >
        {/* Left: rows */}
        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
          {/* Row 1: icon + display name (title > slug > branch) */}
          <div className="flex min-w-0 items-center gap-1.5">
            <WorkspaceStatusMenu
              currentStatus={workspace.status}
              onStatusChange={(status) => onStatusChange?.(workspace.id, status)}
            >
              <button
                type="button"
                onClick={(e) => e.stopPropagation()}
                className="flex h-5 w-5 shrink-0 items-center justify-center rounded transition-opacity hover:opacity-80"
                aria-label={`Status: ${workspace.status}`}
              >
                {hasSessionIcon ? (
                  match(displayStatus)
                    .with("working", () => (
                      <CircularPixelGrid variant="working" size={14} resolution={8} />
                    ))
                    .with("error", () => <span className="bg-accent-red h-2 w-2 rounded-full" />)
                    .otherwise(() => <span className="bg-accent-gold h-2 w-2 rounded-full" />)
                ) : (
                  <WorkflowStatusIcon status={workspace.status} size={14} />
                )}
              </button>
            </WorkspaceStatusMenu>
            <span
              className={cn(
                "truncate text-base",
                isActive
                  ? "text-text-primary font-medium"
                  : isActiveState
                    ? "text-text-primary font-normal"
                    : "text-text-tertiary font-normal"
              )}
            >
              {displayName}
            </span>
          </div>

          {/* Row 2: secondary context · status */}
          <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
            {secondaryText && (
              <span
                className={cn(
                  "truncate text-xs",
                  isActiveState ? "text-text-tertiary" : "text-text-disabled"
                )}
              >
                {secondaryText}
              </span>
            )}
            {showStatusDot && (
              <span
                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
              >
                ·
              </span>
            )}
            {statusText && (
              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
                {isSetupRunning && (
                  <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />
                )}
                {statusText}
              </span>
            )}
          </div>
        </div>

        {/* Right: diff stats */}
        {hasChanges ? (
          <div
            className={cn(
              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
              canArchive && "group-hover/sidebar-row:opacity-0"
            )}
          >
            {additions > 0 && (
              <NumberFlow
                value={additions}
                prefix="+"
                className={isActive ? "text-accent-green" : "text-text-muted"}
              />
            )}
            {deletions > 0 && (
              <NumberFlow
                value={deletions}
                prefix="-"
                className={isActive ? "text-accent-red" : "text-text-muted"}
              />
            )}
          </div>
        ) : null}

        {/* Archive button — hover reveal */}
        {canArchive ? (
          <button
            type="button"
            onClick={handleArchive}
            aria-label={`Archive workspace ${displayName}`}
            title="Archive workspace"
            className={cn(
              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
              "group-hover/sidebar-row:opacity-100"
            )}
          >
            <Archive className="h-3.5 w-3.5" />
          </button>
        ) : null}
      </SidebarRow>
    </div>
  );
});

/**
 * Sidebar Status Configuration System
 *
 * Centralized configuration for workspace/session statuses, priorities, and visual styling.
 * Design philosophy: Make it easy to iterate on colors and priorities without touching component code.
 *
 * @see src/features/session/types.ts for SessionStatus type definition
 */

import type { Workspace } from "@/features/workspace/types";
import type { WorkspaceStatus } from "@shared/enums";

/**
 * Display status extends SessionStatus with derived states.
 * 'unread' is derived from needs_response / needs_plan_response session status.
 */
export type DisplayStatus = "idle" | "working" | "error" | "unread";

/**
 * Priority levels for sorting (higher = more urgent)
 */
export enum StatusPriority {
  ERROR = 4, // Critical - something broke
  UNREAD = 3, // Important - needs review / response
  WORKING = 2, // Active - in progress
  IDLE = 0, // Dormant - no activity
}

/**
 * Visual configuration for each status
 *
 * Design System:
 * - badge: Color for notification badges (collapsed sidebar)
 * - border: Border/glow color for active states
 * - text: Text color for status labels
 * - bg: Background color for sections/cards
 *
 * Color Semantics:
 * 🔴 Red (error) = Critical, blocking, needs immediate action
 * 🟡 Amber (unread) = Important, needs attention when ready
 * 🟢 Green (working) = Active, positive, making progress
 * 🟣 Purple (compacting) = Transient, maintenance, ignore
 * ⚪ Gray (idle) = Dormant, background, low priority
 */
export interface StatusConfig {
  priority: StatusPriority;
  label: string;
  labelActive: string; // Present continuous form (e.g., "Working...")
  badge: string; // Tailwind classes for badge
  border: string; // Tailwind classes for border/glow
  text: string; // Tailwind classes for text
  bg: string; // Tailwind classes for background
  pulse?: boolean; // Whether to animate/pulse
}

/**
 * Status configuration map
 *
 * IMPORTANT: To change colors, edit this object (no component changes needed)
 */
export const STATUS_CONFIG: Record<DisplayStatus, StatusConfig> = {
  error: {
    priority: StatusPriority.ERROR,
    label: "Error",
    labelActive: "Error",
    badge: "bg-destructive text-destructive-foreground",
    border: "border-destructive/60",
    text: "text-destructive",
    bg: "bg-destructive/10",
    pulse: true,
  },
  unread: {
    priority: StatusPriority.UNREAD,
    label: "Needs Attention",
    labelActive: "Awaiting Input",
    badge: "bg-status-unread text-status-unread-fg",
    border: "border-status-unread/60",
    text: "text-status-unread",
    bg: "bg-status-unread/10",
    pulse: false,
  },
  working: {
    priority: StatusPriority.WORKING,
    label: "Working",
    labelActive: "Working...",
    badge: "bg-primary text-primary-foreground",
    border: "border-primary/60",
    text: "text-primary",
    bg: "bg-primary/10",
    pulse: true,
  },
  idle: {
    priority: StatusPriority.IDLE,
    label: "Idle",
    labelActive: "Idle",
    badge: "bg-muted text-muted-foreground",
    border: "border-muted",
    text: "text-muted-foreground",
    bg: "bg-muted/30",
    pulse: false,
  },
};

// ── Workflow Status (Linear-style) ────────────────────────────────────────
// Separate from DisplayStatus which shows real-time agent activity.
// Rendered as a small icon to the left of the workspace title.

export interface WorkflowStatusConfig {
  label: string;
  color: string;
}

export const WORKFLOW_STATUS_CONFIG: Record<WorkspaceStatus, WorkflowStatusConfig> = {
  backlog: { label: "Backlog", color: "text-muted-foreground" },
  "in-progress": { label: "In Progress", color: "text-status-in-progress" },
  "in-review": { label: "In Review", color: "text-status-in-review" },
  done: { label: "Done", color: "text-status-done" },
  canceled: { label: "Canceled", color: "text-muted-foreground" },
};

/**
 * Derive display status from workspace data
 *
 * Priority logic:
 * 1. Error — session in error state
 * 2. Unread — agent needs user response OR has unseen activity
 * 3. Working — agent actively processing
 * 4. Idle — dormant
 *
 * @param workspace Workspace data with session info
 * @param hasUnseenActivity Whether the session has activity the user hasn't viewed yet
 * @returns Derived display status for UI rendering
 */
export function getDisplayStatus(workspace: Workspace, hasUnseenActivity = false): DisplayStatus {
  const status = workspace.session_status;

  if (status === "error") return "error";
  if (status === "needs_response" || status === "needs_plan_response") return "unread";
  if (status === "working") return "working";
  if (hasUnseenActivity) return "unread";
  return "idle";
}

/**
 * Sort workspaces by status priority
 * Higher priority statuses appear first
 *
 * @param workspaces Array of workspaces to sort
 * @param unreadSessionIds Optional set of session IDs with unseen activity
 * @returns Sorted array (original array not mutated)
 */
export function sortByStatusPriority<T extends Workspace>(
  workspaces: T[],
  unreadSessionIds?: Set<string>
): T[] {
  return [...workspaces].sort((a, b) => {
    const hasUnreadA = !!(a.current_session_id && unreadSessionIds?.has(a.current_session_id));
    const hasUnreadB = !!(b.current_session_id && unreadSessionIds?.has(b.current_session_id));
    const statusA = getDisplayStatus(a, hasUnreadA);
    const statusB = getDisplayStatus(b, hasUnreadB);
    const priorityA = STATUS_CONFIG[statusA].priority;
    const priorityB = STATUS_CONFIG[statusB].priority;

    // Higher priority first
    if (priorityA !== priorityB) {
      return priorityB - priorityA;
    }

    // Same priority: sort by latest activity (most recent first)
    const timeA = new Date(a.updated_at).getTime();
    const timeB = new Date(b.updated_at).getTime();
    return timeB - timeA;
  });
}

