203→                      </div>
204→                    )}
205→                  </div>
206→                </SortableTab>
207→              );
208→            })}
209→          </SortableContext>
210→        </DndContext>
211→
212→        {/* New tab button — stays adjacent to tabs */}
213→        {onTabAdd && (
