 18→/**
 19→ * WorkspaceItem — Sidebar workspace row
 20→ *
 21→ * Layout:  [Left (flex-1)]  [Right]
 22→ *   Left:
 23→ *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 24→ *     Row 2: [pad-left 26px] [secondary · status]
 25→ *   Right:
 26→ *     [+additions -deletions]
 27→ *
 28→ * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 29→ * Secondary line: shows slug when title is primary, otherwise just status info.
 30→ *
 31→ * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 32→ * Idle → no icon (26px indent).
 33→ *
 34→ * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 35→ */
 36→export const WorkspaceItem = React.memo(function WorkspaceItem({
 37→  workspace,
 38→  isActive,
 39→  diffStats,
 40→  onClick,
 41→  onArchive,
 42→  onStatusChange,
 43→}: WorkspaceItemProps) {
 44→  const isInitializing = workspace.state === "initializing";
 45→
 46→  // Hooks must be called unconditionally (React rules of hooks)
 47→  const { duration } = useWorkingDuration({
 48→    status: workspace.session_status,
 49→    latestMessageSentAt: workspace.latest_message_sent_at,
 50→  });
 51→
 52→  // Check all sessions in this workspace's tabs for unseen activity,
 53→  // not just current_session_id — the user may have multiple tabs open.
 54→  const tabSessionIds = useWorkspaceLayoutStore(
 55→    (s) => s.layouts[workspace.id]?.chatTabSessionIds
 56→  );
 57→  const hasUnseenActivity = useUnreadStore((s) => {
 58→    const ids = tabSessionIds?.length ? tabSessionIds : workspace.current_session_id ? [workspace.current_session_id] : [];
 59→    return ids.some((sid) => s.unreadSessionIds[sid]);
 60→  });
 61→
 62→  // Initializing state: non-interactive row with loading animation
 63→  if (isInitializing) {
