 1→/**
 2→ * Tracks sessions with unseen activity (agent finished while user wasn't looking).
 3→ * Persisted to localStorage so indicators survive app restarts.
 4→ */
 5→
 6→import { create } from "zustand";
 7→import { devtools, persist } from "zustand/middleware";
 8→
 9→interface UnreadStore {
10→  /** Set of session IDs with unseen activity */
11→  unreadSessionIds: Record<string, true>;
12→
13→  /** Mark a session as having unseen activity */
14→  markUnread: (sessionId: string) => void;
15→
16→  /** Mark a session as read (user viewed it) */
17→  markRead: (sessionId: string) => void;
18→}
19→
20→export const useUnreadStore = create<UnreadStore>()(
21→  devtools(
22→    persist(
23→      (set) => ({
24→        unreadSessionIds: {},
25→
26→        markUnread: (sessionId) =>
27→          set(
28→            (state) => ({
29→              unreadSessionIds: { ...state.unreadSessionIds, [sessionId]: true as const },
30→            }),
31→            false,
32→            "unread/markUnread"
33→          ),
34→
35→        markRead: (sessionId) =>
36→          set(
37→            (state) => {
38→              if (!state.unreadSessionIds[sessionId]) return state;
39→              const { [sessionId]: _, ...rest } = state.unreadSessionIds;
40→              return { unreadSessionIds: rest };
41→            },
42→            false,
43→            "unread/markRead"
44→          ),
45→      }),
46→      {
47→        name: "unread-sessions-store",
48→        version: 1,
49→      }
50→    ),
51→    {
52→      name: "unread-sessions-store",
53→      enabled: import.meta.env.DEV,
54→    }
55→  )
56→);
57→
58→export const unreadActions = {
59→  markUnread: (sessionId: string) => useUnreadStore.getState().markUnread(sessionId),
60→  markRead: (sessionId: string) => useUnreadStore.getState().markRead(sessionId),
61→};
