431→ */
432→export function useStopSession() {
433→  const queryClient = useQueryClient();
434→
435→  return useMutation({
436→    mutationFn: (sessionId: string) => SessionService.stop(sessionId),
437→    onSuccess: (_, sessionId) => {
438→      const session = queryClient.getQueryData<Session>(queryKeys.sessions.detail(sessionId));
439→      track("session_stopped", {
440→        session_id: sessionId,
441→        agent_type: session?.agent_type,
442→      });
443→      // Immediate invalidation for snappy UI feedback.
444→      // Backend also pushes via WS q:invalidate. React Query deduplicates.
445→      queryClient.invalidateQueries({
446→        queryKey: queryKeys.sessions.detail(sessionId),
447→      });
448→      queryClient.invalidateQueries({
449→        queryKey: queryKeys.workspaces.all,
450→      });
451→    },
452→  });
453→}
