456→ * Create a new session for a workspace.
457→ * Used when user opens a new chat tab (Cmd+T).
458→ * Backend creates the session and updates workspace.current_session_id.
459→ */
460→export function useCreateSession() {
461→  const queryClient = useQueryClient();
462→
463→  return useMutation({
464→    mutationFn: (workspaceId: string) => SessionService.createSession(workspaceId),
465→    onSuccess: (newSession, workspaceId) => {
466→      track("session_created", {
467→        workspace_id: workspaceId,
468→        agent_type: newSession?.agent_type,
469→        model: newSession?.model,
470→      });
471→      // Immediate invalidation for snappy UI feedback.
472→      // Backend also pushes via WS q:invalidate. React Query deduplicates.
473→      queryClient.invalidateQueries({
474→        queryKey: queryKeys.workspaces.all,
475→      });
476→      queryClient.invalidateQueries({
477→        queryKey: queryKeys.workspaces.detail(workspaceId),
478→      });
479→      queryClient.invalidateQueries({
480→        queryKey: queryKeys.sessions.byWorkspace(workspaceId),
481→      });
482→    },
483→  });
